import React, { useState, useEffect, useMemo } from 'react';
import { HashRouter, Routes, Route, Navigate, Link, useNavigate, useParams } from 'react-router-dom';
import { AppState, User, Institution, Region, UserRole } from './types';
import { MOCK_USERS, MOCK_INSTITUTIONS } from './mockData';

// Pages
import HomePage from './pages/HomePage';
import BrowsePage from './pages/BrowsePage';
import InstitutionProfile from './pages/InstitutionProfile';
import AuthPage from './pages/AuthPage';
import SuperAdminDashboard from './pages/SuperAdminDashboard';
import InstitutionAdminDashboard from './pages/InstitutionAdminDashboard';

// Components
import Navbar from './components/Navbar';
import Footer from './components/Footer';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('se_user');
    return saved ? JSON.parse(saved) : null;
  });

  const [institutions, setInstitutions] = useState<Institution[]>(() => {
    const saved = localStorage.getItem('se_institutions');
    return saved ? JSON.parse(saved) : MOCK_INSTITUTIONS;
  });

  const [selectedRegion, setSelectedRegion] = useState<Region | null>(() => {
    const saved = localStorage.getItem('se_region');
    return saved ? (saved as Region) : null;
  });

  useEffect(() => {
    localStorage.setItem('se_user', JSON.stringify(user));
  }, [user]);

  useEffect(() => {
    localStorage.setItem('se_institutions', JSON.stringify(institutions));
  }, [institutions]);

  useEffect(() => {
    if (selectedRegion) {
      localStorage.setItem('se_region', selectedRegion);
    }
  }, [selectedRegion]);

  const handleLogin = (u: User) => setUser(u);
  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('se_user');
  };

  const updateInstitution = (updated: Institution) => {
    setInstitutions(prev => prev.map(i => i.id === updated.id ? updated : i));
  };

  const addInstitution = (newInst: Institution) => {
    setInstitutions(prev => [...prev, newInst]);
  };

  const deleteInstitution = (id: string) => {
    setInstitutions(prev => prev.filter(i => i.id !== id));
  };

  return (
    <HashRouter>
      <div className="min-h-screen flex flex-col bg-slate-50">
        <Navbar user={user} onLogout={handleLogout} />

        <main className="flex-grow">
          <Routes>
            <Route path="/" element={<HomePage onSelectRegion={setSelectedRegion} />} />
            <Route path="/browse" element={<BrowsePage institutions={institutions} region={selectedRegion} onSelectRegion={setSelectedRegion} />} />
            <Route path="/school/:slug" element={<InstitutionProfile institutions={institutions} />} />
            <Route path="/auth" element={user ? <Navigate to="/dashboard" /> : <AuthPage onLogin={handleLogin} />} />

            {/* Protected Routes */}
            <Route 
              path="/dashboard" 
              element={
                !user ? <Navigate to="/auth" /> : 
                user.role === UserRole.SUPER_ADMIN ? 
                  <SuperAdminDashboard 
                    institutions={institutions} 
                    users={MOCK_USERS} 
                    onUpdate={updateInstitution} 
                    onDelete={deleteInstitution} 
                  /> : 
                  <InstitutionAdminDashboard 
                    user={user} 
                    institutions={institutions} 
                    onUpdate={updateInstitution} 
                    onAdd={addInstitution}
                  />
              } 
            />

            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </main>

        <Footer />
      </div>
    </HashRouter>
  );
};

export default App;

