import React, { useState } from 'react';
import { Institution, User, Region, InstitutionType } from '../types';

interface InstitutionAdminDashboardProps {
  user: User;
  institutions: Institution[];
  onUpdate: (inst: Institution) => void;
  onAdd: (inst: Institution) => void;
}

const InstitutionAdminDashboard: React.FC<InstitutionAdminDashboardProps> = ({ user, institutions, onUpdate, onAdd }) => {
  const [editingId, setEditingId] = useState<string | null>(user.institutionId || null);
  const inst = institutions.find(i => i.id === editingId);

  // Simple state for building a NEW institution if none exists
  const [isCreating, setIsCreating] = useState(!user.institutionId);
  const [formData, setFormData] = useState<Partial<Institution>>({
    name: '',
    region: Region.HHOHHO,
    type: [InstitutionType.HIGH_SCHOOL],
    status: 'pending',
    contact: { address: '', phone: '', email: '' },
    sections: {
      homepage: { title: 'Welcome', content: '', enabled: true },
      about: { title: 'About Us', content: '', enabled: true },
      admissions: { title: 'Admissions', content: '', enabled: true },
      academics: { title: 'Academics', content: '', enabled: true },
      studentLife: { title: 'Student Life', content: '', enabled: false },
      news: { title: 'News', content: '', enabled: false },
      contact: { title: 'Contact Us', content: '', enabled: true }
    },
    stats: { views: 0, applications: 0 }
  });

  const handleCreate = (e: React.FormEvent) => {
    e.preventDefault();
    const newId = `inst-${Date.now()}`;
    const newInst: Institution = {
      ...(formData as any),
      id: newId,
      slug: (formData.name || '').toLowerCase().replace(/\s+/g, '-'),
      logo: 'https://picsum.photos/seed/newschool/200/200',
      coverImage: 'https://picsum.photos/seed/newschoolcover/1200/400',
      adminId: user.id
    };
    onAdd(newInst);
    setIsCreating(false);
    setEditingId(newId);
  };

  const handleSectionUpdate = (key: keyof typeof inst.sections, field: 'content' | 'enabled' | 'title', value: any) => {
    if (!inst) return;
    const updated = {
      ...inst,
      sections: {
        ...inst.sections,
        [key]: { ...inst.sections[key], [field]: value }
      }
    };
    onUpdate(updated);
  };

  if (isCreating) {
    return (
      <div className="max-w-3xl mx-auto px-4 py-16">
        <h1 className="text-3xl font-bold text-slate-900 mb-8">Register Your Institution</h1>
        <form onSubmit={handleCreate} className="bg-white p-8 rounded-2xl shadow-xl border border-slate-100 space-y-6">
          <div>
            <label className="block text-sm font-bold text-slate-700 mb-2">Institution Name</label>
            <input 
              required
              type="text" 
              className="w-full border-slate-200 border rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500" 
              placeholder="e.g. Mbabane Central High"
              value={formData.name}
              onChange={e => setFormData({ ...formData, name: e.target.value })}
            />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-bold text-slate-700 mb-2">Region</label>
              <select 
                className="w-full border-slate-200 border rounded-xl px-4 py-3"
                value={formData.region}
                onChange={e => setFormData({ ...formData, region: e.target.value as Region })}
              >
                {Object.values(Region).map(r => <option key={r} value={r}>{r}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-sm font-bold text-slate-700 mb-2">Primary Type</label>
              <select className="w-full border-slate-200 border rounded-xl px-4 py-3">
                {Object.values(InstitutionType).map(t => <option key={t} value={t}>{t}</option>)}
              </select>
            </div>
          </div>
          <button type="submit" className="w-full bg-blue-600 text-white font-bold py-4 rounded-xl shadow-lg hover:bg-blue-700 transition-colors">
            Start Building Profile
          </button>
        </form>
      </div>
    );
  }

  if (!inst) return <div className="p-20 text-center">Loading institution data...</div>;

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-4">
        <div>
          <div className="flex items-center gap-2 mb-1">
            <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase ${inst.status === 'published' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'}`}>
              {inst.status}
            </span>
            <span className="text-slate-400 text-xs font-medium">Last updated: Today</span>
          </div>
          <h1 className="text-3xl font-bold text-slate-900">{inst.name}</h1>
        </div>
        <div className="flex gap-3">
          <a href={`#/school/${inst.slug}`} target="_blank" className="bg-white border border-slate-200 text-slate-700 px-6 py-2.5 rounded-xl font-bold hover:bg-slate-50 transition-colors flex items-center">
            <svg className="w-4 h-4 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" /></svg>
            Preview Site
          </a>
          <button className="bg-blue-600 text-white px-6 py-2.5 rounded-xl font-bold shadow-lg hover:bg-blue-700 transition-colors">
            Publish Changes
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
        {/* Navigation Sidebar */}
        <aside className="lg:col-span-1">
          <div className="bg-white border border-slate-200 rounded-2xl overflow-hidden sticky top-24">
            <div className="p-4 bg-slate-50 border-b border-slate-200">
              <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest">Builder Sections</h3>
            </div>
            <div className="divide-y divide-slate-100">
              {Object.keys(inst.sections).map(key => {
                const s = inst.sections[key as keyof typeof inst.sections];
                return (
                  <button 
                    key={key}
                    className="w-full flex items-center justify-between p-4 text-left hover:bg-blue-50 transition-colors group"
                  >
                    <div className="flex items-center">
                      <div className={`w-2 h-2 rounded-full mr-3 ${s.enabled ? 'bg-emerald-500' : 'bg-slate-300'}`}></div>
                      <span className="text-sm font-semibold text-slate-700 group-hover:text-blue-600">{s.title}</span>
                    </div>
                    {!s.enabled && <span className="text-[10px] text-slate-400 font-bold uppercase">Disabled</span>}
                  </button>
                );
              })}
            </div>
          </div>

          <div className="mt-8 bg-slate-900 rounded-2xl p-6 text-white">
            <h4 className="text-sm font-bold mb-4 flex items-center">
              <svg className="w-4 h-4 mr-2 text-blue-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" /></svg>
              Quick Analytics
            </h4>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <p className="text-[10px] text-slate-400 uppercase font-bold">Views</p>
                <p className="text-xl font-bold">{inst.stats.views}</p>
              </div>
              <div>
                <p className="text-[10px] text-slate-400 uppercase font-bold">Apps</p>
                <p className="text-xl font-bold">{inst.stats.applications}</p>
              </div>
            </div>
          </div>
        </aside>

        {/* Editor Main */}
        <div className="lg:col-span-3 space-y-8">
           <div className="bg-white border border-slate-200 rounded-2xl p-8 shadow-sm">
             <div className="flex items-center justify-between mb-8">
                <h2 className="text-xl font-bold text-slate-900">Edit Section: Homepage</h2>
                <div className="flex items-center">
                  <span className="text-sm text-slate-500 mr-3">Section Enabled</span>
                  <button 
                    onClick={() => handleSectionUpdate('homepage', 'enabled', !inst.sections.homepage.enabled)}
