import React, { useState, useEffect } from 'react';
import { useSearchParams, useNavigate } from 'react-router-dom';
import { User, UserRole } from '../types';
import { MOCK_USERS } from '../mockData';

interface AuthPageProps {
  onLogin: (user: User) => void;
}

const AuthPage: React.FC<AuthPageProps> = ({ onLogin }) => {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState<'login' | 'register'>('login');

  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [error, setError] = useState('');

  useEffect(() => {
    const tab = searchParams.get('tab');
    if (tab === 'register') setActiveTab('register');
  }, [searchParams]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (activeTab === 'login') {
      const foundUser = MOCK_USERS.find(u => u.email === email);
      if (foundUser) {
        onLogin(foundUser);
        navigate('/dashboard');
      } else {
        // Simple mock for allowing "Institution Admin" roles easily
        if (email.includes('school')) {
            const newUser: User = {
                id: `user-${Date.now()}`,
                email,
                name: email.split('@')[0],
                role: UserRole.INSTITUTION_ADMIN,
                isVerified: true
            };
            onLogin(newUser);
            navigate('/dashboard');
        } else {
            setError('Invalid credentials for mock. (Hint: use "admin@schoolseswatini.com" or an email with "school" in it)');
        }
      }
    } else {
      const newUser: User = {
        id: `user-${Date.now()}`,
        email,
        name,
        role: UserRole.INSTITUTION_ADMIN,
        isVerified: false
      };
      onLogin(newUser);
      navigate('/dashboard');
    }
  };

  return (
    <div className="min-h-[calc(100vh-64px)] flex items-center justify-center py-12 px-4 sm:px-6 lg:px-8 bg-slate-50">
      <div className="max-w-md w-full space-y-8 bg-white p-10 rounded-3xl shadow-xl border border-slate-100">
        <div>
          <h2 className="mt-6 text-center text-3xl font-extrabold text-slate-900">
            {activeTab === 'login' ? 'Welcome back' : 'Create an account'}
          </h2>
          <p className="mt-2 text-center text-sm text-slate-500">
            {activeTab === 'login' ? 'Access your institution dashboard' : 'Register your school to build your mini-site'}
          </p>
        </div>

        <div className="flex border-b border-slate-100">
          <button
            onClick={() => setActiveTab('login')}
            className={`flex-1 py-4 text-sm font-bold uppercase tracking-wider border-b-2 transition-colors ${activeTab === 'login' ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-400 hover:text-slate-600'}`}
          >
            Login
          </button>
          <button
            onClick={() => setActiveTab('register')}
            className={`flex-1 py-4 text-sm font-bold uppercase tracking-wider border-b-2 transition-colors ${activeTab === 'register' ? 'border-blue-600 text-blue-600' : 'border-transparent text-slate-400 hover:text-slate-600'}`}
          >
            Register
          </button>
        </div>

        <form className="mt-8 space-y-6" onSubmit={handleSubmit}>
          {error && <div className="p-3 text-sm text-rose-600 bg-rose-50 rounded-lg border border-rose-100">{error}</div>}

          <div className="rounded-md shadow-sm -space-y-px">
            {activeTab === 'register' && (
              <div className="mb-4">
                <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Full Name</label>
                <input
                  required
                  type="text"
                  className="appearance-none relative block w-full px-4 py-3 border border-slate-200 placeholder-slate-400 text-slate-900 rounded-xl focus:outline-none focus:ring-blue-500 focus:border-blue-500 sm:text-sm"
                  placeholder="e.g. John Doe"
                  value={name}
                  onChange={e => setName(e.target.value)}
                />
              </div>
            )}
            <div className="mb-4">
              <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Email address</label>
              <input
                required
                type="email"
                className="appearance-none relative block w-full px-4 py-3 border border-slate-200 placeholder-slate-400 text-slate-900 rounded-xl focus:outline-none focus:ring-blue-500 focus:border-blue-500 sm:text-sm"
                placeholder="admin@yourschool.sz"
                value={email}
                onChange={e => setEmail(e.target.value)}
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Password</label>
              <input
                required
                type="password"
                className="appearance-none relative block w-full px-4 py-3 border border-slate-200 placeholder-slate-400 text-slate-900 rounded-xl focus:outline-none focus:ring-blue-500 focus:border-blue-500 sm:text-sm"
                placeholder="••••••••"
                value={password}
                onChange={e => setPassword(e.target.value)}
              />
            </div>
          </div>

