import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import { User, Institution, Region, UserRole } from './types';
import { MOCK_USERS, MOCK_INSTITUTIONS } from './mockData';

// Pages
import HomePage from './pages/HomePage';
import BrowsePage from './pages/BrowsePage';
import InstitutionProfile from './pages/InstitutionProfile';
import AuthPage from './pages/AuthPage';
import SuperAdminDashboard from './pages/SuperAdminDashboard';
import InstitutionAdminDashboard from './pages/InstitutionAdminDashboard';

// Components
import Navbar from './components/Navbar';
import Footer from './components/Footer';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('se_user');
    return saved ? JSON.parse(saved) : null;
  });

  const [institutions, setInstitutions] = useState<Institution[]>(() => {
    const saved = localStorage.getItem('se_institutions');
    return saved ? JSON.parse(saved) : MOCK_INSTITUTIONS;
  });

  const [selectedRegion, setSelectedRegion] = useState<Region | null>(() => {
    const saved = localStorage.getItem('se_region');
    return saved ? (saved as Region) : null;
  });

  const [favorites, setFavorites] = useState<string[]>(() => {
    const saved = localStorage.getItem('se_favorites');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('se_user', JSON.stringify(user));
  }, [user]);

  useEffect(() => {
    localStorage.setItem('se_institutions', JSON.stringify(institutions));
  }, [institutions]);

  useEffect(() => {
    localStorage.setItem('se_favorites', JSON.stringify(favorites));
  }, [favorites]);

  useEffect(() => {
    if (selectedRegion) {
      localStorage.setItem('se_region', selectedRegion);
    }
  }, [selectedRegion]);

  const handleLogin = (u: User) => setUser(u);
  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('se_user');
  };

  const updateInstitution = (updated: Institution) => {
    setInstitutions(prev => prev.map(i => i.id === updated.id ? updated : i));
  };

  const addInstitution = (newInst: Institution) => {
    setInstitutions(prev => [...prev, newInst]);
  };

  const deleteInstitution = (id: string) => {
    setInstitutions(prev => prev.filter(i => i.id !== id));
  };

  const toggleFavorite = (id: string) => {
    setFavorites(prev => prev.includes(id) ? prev.filter(f => f !== id) : [...prev, id]);
  };

  return (
    <HashRouter>
      <div className="min-h-screen flex flex-col bg-slate-50">
        <Navbar user={user} onLogout={handleLogout} />

        <main className="flex-grow">
          <Routes>
            <Route path="/" element={<HomePage onSelectRegion={setSelectedRegion} />} />
            <Route 
              path="/browse" 
              element={
                <BrowsePage 
                  institutions={institutions} 
                  region={selectedRegion} 
                  onSelectRegion={setSelectedRegion} 
                  favorites={favorites}
                  onToggleFavorite={toggleFavorite}
                />
              } 
            />
            <Route 
              path="/school/:slug" 
              element={
                <InstitutionProfile 
                  institutions={institutions} 
                  favorites={favorites}
                  onToggleFavorite={toggleFavorite}
                />
              } 
            />
            <Route path="/auth" element={user ? <Navigate to="/dashboard" /> : <AuthPage onLogin={handleLogin} />} />

            <Route 
              path="/dashboard" 
              element={
                !user ? <Navigate to="/auth" /> : 
                user.role === UserRole.SUPER_ADMIN ? 
                  <SuperAdminDashboard 
                    institutions={institutions} 
                    users={MOCK_USERS} 
                    onUpdate={updateInstitution} 
                    onDelete={deleteInstitution} 
                  /> : 
                  <InstitutionAdminDashboard 
                    user={user} 
                    institutions={institutions} 
                    onUpdate={updateInstitution} 
                    onAdd={addInstitution}
                  />
              } 
            />

            <Route path="*" element={<Navigate to="/" />} />
          </Routes>
        </main>

        <Footer />
      </div>
    </HashRouter>
  );
};

export default App;

import React, { useState } from 'react';
import { Institution, User, Region, InstitutionType } from '../types';
import { GoogleGenAI } from "@google/genai";

interface InstitutionAdminDashboardProps {
  user: User;
  institutions: Institution[];
  onUpdate: (inst: Institution) => void;
  onAdd: (inst: Institution) => void;
}

const InstitutionAdminDashboard: React.FC<InstitutionAdminDashboardProps> = ({ user, institutions, onUpdate, onAdd }) => {
  const [editingId, setEditingId] = useState<string | null>(user.institutionId || null);
  const inst = institutions.find(i => i.id === editingId);
  const [isAiLoading, setIsAiLoading] = useState(false);

  const [isCreating, setIsCreating] = useState(!user.institutionId && !editingId);
  const [formData, setFormData] = useState<Partial<Institution>>({
    name: '',
    region: Region.HHOHHO,
    type: [InstitutionType.HIGH_SCHOOL],
    status: 'pending',
    contact: { address: '', phone: '', email: '' },
    sections: {
      homepage: { title: 'Welcome', content: '', enabled: true },
      about: { title: 'About Us', content: '', enabled: true },
      admissions: { title: 'Admissions', content: '', enabled: true },
      academics: { title: 'Academics', content: '', enabled: true },
      studentLife: { title: 'Student Life', content: '', enabled: false },
      news: { title: 'News', content: '', enabled: false },
      contact: { title: 'Contact Us', content: '', enabled: true }
    },
    stats: { views: 0, applications: 0 }
  });

  const handleCreate = (e: React.FormEvent) => {
    e.preventDefault();
    const newId = `inst-${Date.now()}`;
    const newInst: Institution = {
      ...(formData as any),
      id: newId,
      slug: (formData.name || '').toLowerCase().replace(/\s+/g, '-'),
      logo: 'https://picsum.photos/seed/newschool/200/200',
      coverImage: 'https://picsum.photos/seed/newschoolcover/1200/400',
      adminId: user.id
    };
    onAdd(newInst);
    setIsCreating(false);
    setEditingId(newId);
  };

  const handleSectionUpdate = (key: keyof typeof inst.sections, field: 'content' | 'enabled' | 'title', value: any) => {
    if (!inst) return;
    const updated = {
      ...inst,
      sections: {
        ...inst.sections,
        [key]: { ...inst.sections[key], [field]: value }
      }
    };
    onUpdate(updated);
  };

  const handleAiAssist = async (key: keyof typeof inst.sections) => {
    if (!inst) return;
    setIsAiLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Act as an expert school administrator in Eswatini. Write a compelling, professional, and inspiring "${inst.sections[key].title}" section for a school named "${inst.name}" located in ${inst.region}. Focus on excellence, community, and the unique cultural heritage of Eswatini. Keep it under 200 words.`;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });

      const generatedText = response.text || "Failed to generate content.";
      handleSectionUpdate(key, 'content', generatedText.trim());
    } catch (error) {
      console.error("AI Generation failed:", error);
      alert("AI Assistant is currently unavailable. Please try again later.");
    } finally {
      setIsAiLoading(false);
    }
  };

  if (isCreating) {
    return (
      <div className="max-w-3xl mx-auto px-4 py-16">
        <h1 className="text-3xl font-bold text-slate-900 mb-8">Register Your Institution</h1>
        <form onSubmit={handleCreate} className="bg-white p-8 rounded-2xl shadow-xl border border-slate-100 space-y-6">
          <div>
            <label className="block text-sm font-bold text-slate-700 mb-2">Institution Name</label>
            <input 
              required
              type="text" 
              className="w-full border-slate-200 border rounded-xl px-4 py-3 focus:ring-2 focus:ring-blue-500" 
              placeholder="e.g. Mbabane Central High"
              value={formData.name}
              onChange={e => setFormData({ ...formData, name: e.target.value })}
            />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-bold text-slate-700 mb-2">Region</label>
              <select 
                className="w-full border-slate-200 border rounded-xl px-4 py-3"
                value={formData.region}
                onChange={e => setFormData({ ...formData, region: e.target.value as Region })}
              >
                {Object.values(Region).map(r => <option key={r} value={r}>{r}</option>)}
              </select>
            </div>
            <div>
              <label className="block text-sm font-bold text-slate-700 mb-2">Primary Type</label>
              <select className="w-full border-slate-200 border rounded-xl px-4 py-3">
                {Object.values(InstitutionType).map(t => <option key={t} value={t}>{t}</option>)}
              </select>
            </div>
          </div>
          <button type="submit" className="w-full bg-blue-600 text-white font-bold py-4 rounded-xl shadow-lg hover:bg-blue-700 transition-colors">
            Start Building Profile
          </button>
        </form>
      </div>
    );
  }

  if (!inst) return <div className="p-20 text-center">Loading institution data...</div>;

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-4">
        <div>
          <div className="flex items-center gap-2 mb-1">
            <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase ${inst.status === 'published' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'}`}>
              {inst.status}
            </span>
            <span className="text-slate-400 text-xs font-medium">Last updated: Today</span>
          </div>
          <h1 className="text-3xl font-bold text-slate-900">{inst.name}</h1>
        </div>
        <div className="flex gap-3">
          <a href={`#/school/${inst.slug}`} target="_blank" className="bg-white border border-slate-200 text-slate-700 px-6 py-2.5 rounded-xl font-bold hover:bg-slate-50 transition-colors flex items-center">
            <svg className="w-4 h-4 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" /></svg>
            Preview Site
          </a>
          <button className="bg-blue-600 text-white px-6 py-2.5 rounded-xl font-bold shadow-lg hover:bg-blue-700 transition-colors">
            Publish Changes
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
        <aside className="lg:col-span-1">
          <div className="bg-white border border-slate-200 rounded-2xl overflow-hidden sticky top-24">
            <div className="p-4 bg-slate-50 border-b border-slate-200">
              <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest">Builder Sections</h3>
            </div>
            <div className="divide-y divide-slate-100">
              {(Object.keys(inst.sections) as Array<keyof typeof inst.sections>).map(key => {
                const s = inst.sections[key];
                return (
                  <button 
                    key={key}
                    className="w-full flex items-center justify-between p-4 text-left hover:bg-blue-50 transition-colors group"
