                );
              })}
            </div>
          </div>
        </aside>

        <div className="lg:col-span-3 space-y-8">
           <div className="bg-white border border-slate-200 rounded-2xl p-8 shadow-sm">
             <div className="flex items-center justify-between mb-8">
