                <div className="flex items-center">
                  <span className="text-sm text-slate-500 mr-3">Section Enabled</span>
                  <button 
                    onClick={() => handleSectionUpdate('homepage', 'enabled', !inst.sections.homepage.enabled)}
                    className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${inst.sections.homepage.enabled ? 'bg-blue-600' : 'bg-slate-300'}`}
                  >
                    <span className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${inst.sections.homepage.enabled ? 'translate-x-6' : 'translate-x-1'}`} />
