import React, { useState, useMemo, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { Institution, Region, InstitutionType } from '../types';
import { GoogleGenAI } from "@google/genai";

interface BrowsePageProps {
  institutions: Institution[];
  region: Region | null;
  onSelectRegion: (region: Region) => void;
  favorites: string[];
  onToggleFavorite: (id: string) => void;
}

const BrowsePage: React.FC<BrowsePageProps> = ({ institutions, region, onSelectRegion, favorites, onToggleFavorite }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedType, setSelectedType] = useState<string>('All');
  const [smartInsight, setSmartInsight] = useState<{ text: string; links: any[] } | null>(null);
  const [isInsightLoading, setIsInsightLoading] = useState(false);

  const filteredInstitutions = useMemo(() => {
    return institutions.filter(inst => {
      const matchesRegion = region ? inst.region === region : true;
      const matchesSearch = inst.name.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesType = selectedType === 'All' || inst.type.some(t => t === selectedType);
      return matchesRegion && matchesSearch && matchesType && inst.status === 'published';
    });
  }, [institutions, region, searchTerm, selectedType]);

  const fetchSmartInsight = async () => {
    if (searchTerm.length < 4) return;
    setIsInsightLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Provide a brief summary of the education landscape or specific institutions related to "${searchTerm}" in Eswatini. Mention any recent achievements or news if applicable.`,
        config: { tools: [{ googleSearch: {} }] },
      });

      const text = response.text || "";
      const links = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
      setSmartInsight({ text, links });
    } catch (e) {
      console.error(e);
    } finally {
      setIsInsightLoading(false);
    }
  };

  useEffect(() => {
    const timer = setTimeout(() => {
      if (searchTerm) fetchSmartInsight();
    }, 1500);
    return () => clearTimeout(timer);
  }, [searchTerm]);

  const allTypes = ['All', ...Object.values(InstitutionType)];

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
      <div className="mb-10">
        <h1 className="text-3xl font-bold text-slate-900 mb-2">
          {region ? `${region} Region` : 'Explore All Institutions'}
        </h1>
        <p className="text-slate-500">Discover and compare the best educational institutions across Eswatini.</p>
      </div>

      <div className="flex flex-col lg:flex-row gap-8">
        <aside className="w-full lg:w-64 space-y-8">
          <div>
            <label className="block text-sm font-semibold text-slate-700 mb-3 uppercase tracking-wider">Region</label>
            <div className="grid grid-cols-2 lg:grid-cols-1 gap-2">
              {Object.values(Region).map(r => (
                <button
                  key={r}
                  onClick={() => onSelectRegion(r)}
                  className={`px-4 py-2 text-left text-sm rounded-lg transition-colors ${region === r ? 'bg-blue-600 text-white shadow-md' : 'bg-white text-slate-600 hover:bg-slate-100'}`}
                >
                  {r}
                </button>
              ))}
            </div>
          </div>

          <div className="bg-blue-50 border border-blue-100 rounded-2xl p-6">
            <h4 className="text-sm font-bold text-blue-800 mb-3 flex items-center">
              <svg className="w-4 h-4 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
              Smart Insights
            </h4>
            {isInsightLoading ? (
               <div className="animate-pulse space-y-2">
                 <div className="h-3 bg-blue-200 rounded w-full"></div>
                 <div className="h-3 bg-blue-200 rounded w-4/5"></div>
               </div>
            ) : smartInsight ? (
              <div className="text-xs text-blue-700 leading-relaxed">
                <p className="mb-2">{smartInsight.text}</p>
                {smartInsight.links.length > 0 && (
                  <div className="border-t border-blue-200 pt-2 mt-2">
                    <p className="font-bold mb-1">Sources:</p>
