                )}
              </div>
            ) : (
              <p className="text-xs text-slate-500 italic">Type a name to see AI-powered regional education insights.</p>
            )}
          </div>
        </aside>

        <div className="flex-1">
          <div className="mb-8 flex flex-col md:flex-row gap-4">
            <div className="relative flex-1">
              <span className="absolute inset-y-0 left-0 pl-3 flex items-center text-slate-400">
                <svg className="h-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
              </span>
              <input
