import React, { useState, useEffect } from 'react';
import { useParams, Navigate } from 'react-router-dom';
import { Institution } from '../types';
import { GoogleGenAI } from "@google/genai";

interface InstitutionProfileProps {
  institutions: Institution[];
  favorites: string[];
  onToggleFavorite: (id: string) => void;
}

const InstitutionProfile: React.FC<InstitutionProfileProps> = ({ institutions, favorites, onToggleFavorite }) => {
  const { slug } = useParams<{ slug: string }>();
  const [activeSection, setActiveSection] = useState<string>('homepage');
  const [nearbyLandmarks, setNearbyLandmarks] = useState<{ name: string; type: string; uri: string }[]>([]);
  const [isMapLoading, setIsMapLoading] = useState(false);

  const inst = institutions.find(i => i.slug === slug);

  useEffect(() => {
    if (inst) {
      fetchNearbyInfo();
    }
  }, [inst?.id]);

  const fetchNearbyInfo = async () => {
    if (!inst) return;
    setIsMapLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      // Using gemini-2.5-flash for maps grounding as per guidelines
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash",
        contents: `What are 3 important landmarks or services (like hospitals, malls, or transport hubs) near ${inst.name} in ${inst.contact.address}, Eswatini?`,
        config: {
          tools: [{ googleMaps: {} }],
        },
      });

      const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
      const landmarks = chunks
        .filter(c => c.maps)
        .map(c => ({
          name: c.maps.title,
          type: 'Landmark',
          uri: c.maps.uri
        }));
      setNearbyLandmarks(landmarks.slice(0, 3));
    } catch (e) {
      console.error("Maps grounding failed", e);
    } finally {
      setIsMapLoading(false);
    }
  };

  if (!inst) return <Navigate to="/browse" />;

  const sectionKeys = Object.keys(inst.sections) as Array<keyof typeof inst.sections>;
  const enabledSections = sectionKeys.filter(key => inst.sections[key].enabled);

  return (
    <div className="min-h-screen bg-white">
      <div className="relative h-[300px] md:h-[450px]">
        <img src={inst.coverImage} alt={inst.name} className="w-full h-full object-cover" />
        <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/20 to-transparent"></div>
        <div className="absolute bottom-0 left-0 w-full">
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 pb-10 flex flex-col md:flex-row items-end gap-6">
            <div className="w-24 h-24 md:w-32 md:h-32 bg-white rounded-2xl p-2 shadow-xl shrink-0 -mb-6 md:-mb-10 border-4 border-white">
              <img src={inst.logo} alt="Logo" className="w-full h-full object-contain" />
            </div>
            <div className="mb-2">
              <div className="flex items-center gap-2 mb-1">
                {inst.isVerified && (
                  <span className="bg-blue-600 text-white p-0.5 rounded-full" title="Verified Institution">
                    <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" /></svg>
                  </span>
                )}
                <span className="text-white/80 text-sm font-medium tracking-wide uppercase">{inst.region} • {inst.type.join(' & ')}</span>
              </div>
              <h1 className="text-3xl md:text-5xl font-extrabold text-white">{inst.name}</h1>
            </div>
            <div className="md:ml-auto flex gap-3 pb-2">
              <button 
                onClick={() => onToggleFavorite(inst.id)}
                className={`p-3 rounded-xl backdrop-blur-md transition-all ${favorites.includes(inst.id) ? 'bg-rose-500 text-white' : 'bg-white/20 text-white hover:bg-white/30'}`}
              >
                <svg className="w-6 h-6" fill={favorites.includes(inst.id) ? "currentColor" : "none"} viewBox="0 0 24 24" stroke="currentColor">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z" />
                </svg>
              </button>
              <button className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-2.5 rounded-xl font-bold shadow-lg transition-transform hover:-translate-y-1">
                Apply Now
              </button>
            </div>
          </div>
        </div>
      </div>

      <div className="bg-slate-50 border-b border-slate-200 sticky top-16 z-40 overflow-x-auto">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <nav className="flex space-x-8 h-14">
            {enabledSections.map((key) => (
              <button
                key={key}
                onClick={() => setActiveSection(key)}
                className={`flex items-center px-1 border-b-2 text-sm font-semibold transition-colors uppercase tracking-tight whitespace-nowrap ${
                  activeSection === key 
                    ? 'border-blue-600 text-blue-600' 
                    : 'border-transparent text-slate-500 hover:text-slate-700'
                }`}
              >
                {inst.sections[key].title}
              </button>
            ))}
          </nav>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-16">
        <div className="flex flex-col lg:flex-row gap-12">
          <div className="flex-grow lg:max-w-3xl">
            <h2 className="text-3xl font-bold text-slate-900 mb-6">{inst.sections[activeSection as keyof typeof inst.sections].title}</h2>
            <div className="prose prose-slate prose-lg max-w-none text-slate-600 leading-relaxed whitespace-pre-wrap">
              {inst.sections[activeSection as keyof typeof inst.sections].content}
            </div>
          </div>

          <aside className="lg:w-80 shrink-0">
            <div className="bg-slate-50 rounded-2xl p-8 border border-slate-100 mb-6">
              <h3 className="text-lg font-bold text-slate-900 mb-6 border-b pb-4">Contact</h3>
              <div className="space-y-6">
                <div>
                  <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Address</label>
                  <p className="text-slate-700 font-medium">{inst.contact.address}</p>
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Phone</label>
                  <p className="text-slate-700 font-medium">{inst.contact.phone}</p>
                </div>
                {inst.contact.website && (
                  <div>
                    <label className="block text-xs font-bold text-slate-400 uppercase mb-1">Official Website</label>
                    <a href={inst.contact.website} target="_blank" rel="noopener noreferrer" className="text-blue-600 font-bold hover:underline">
                      Visit Website
                    </a>
                  </div>
                )}
              </div>
            </div>

            <div className="bg-indigo-50 border border-indigo-100 rounded-2xl p-8 mb-6">
              <h3 className="text-lg font-bold text-indigo-900 mb-4 flex items-center">
                <svg className="w-5 h-5 mr-2" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
                Explore Nearby
              </h3>
              {isMapLoading ? (
                <div className="space-y-3 animate-pulse">
                  <div className="h-4 bg-indigo-200 rounded w-full"></div>
                  <div className="h-4 bg-indigo-200 rounded w-3/4"></div>
                </div>
              ) : nearbyLandmarks.length > 0 ? (
                <ul className="space-y-4">
                  {nearbyLandmarks.map((point, idx) => (
                    <li key={idx} className="group">
                      <a href={point.uri} target="_blank" className="flex items-start">
                        <div className="w-2 h-2 rounded-full bg-indigo-400 mt-2 mr-3 group-hover:bg-indigo-600 transition-colors"></div>
                        <div>
                          <p className="text-sm font-bold text-indigo-900 group-hover:underline leading-tight">{point.name}</p>
                          <p className="text-xs text-indigo-500 uppercase tracking-tighter">View on Map</p>
                        </div>
                      </a>
                    </li>
                  ))}
                </ul>
              ) : (
                <p className="text-sm text-indigo-600 italic">No landmark data available for this location.</p>
              )}
            </div>

            <div className="bg-blue-600 rounded-2xl p-8 text-white shadow-xl">
              <h3 className="text-xl font-bold mb-4">Admissions Open</h3>
              <p className="text-blue-100 text-sm mb-6">Applications for the next intake are now being accepted.</p>
              <button className="w-full bg-white text-blue-600 font-bold py-3 rounded-xl shadow-md hover:bg-blue-50 transition-colors">
                Online Application
              </button>
            </div>
          </aside>
        </div>
      </div>
    </div>
  );
};

