import React, { useState, useMemo, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { Institution, Region, InstitutionType, GenderType } from '../types';
import { GoogleGenAI } from "@google/genai";

interface BrowsePageProps {
  institutions: Institution[];
  region: Region | null;
  onSelectRegion: (region: Region) => void;
  favorites: string[];
  onToggleFavorite: (id: string) => void;
}

const BrowsePage: React.FC<BrowsePageProps> = ({ institutions, region, onSelectRegion, favorites, onToggleFavorite }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedType, setSelectedType] = useState<string>('All');
  const [selectedGender, setSelectedGender] = useState<string>('All');
  const [onlyBoarding, setOnlyBoarding] = useState(false);
  const [smartInsight, setSmartInsight] = useState<{ text: string; links: any[] } | null>(null);
  const [isInsightLoading, setIsInsightLoading] = useState(false);
  const [showFilters, setShowFilters] = useState(false);

  const filteredInstitutions = useMemo(() => {
    return institutions.filter(inst => {
      const matchesRegion = region ? inst.region === region : true;
      const matchesSearch = inst.name.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesType = selectedType === 'All' || inst.type.some(t => t === selectedType);
      const matchesGender = selectedGender === 'All' || inst.metadata.gender === selectedGender;
      const matchesBoarding = !onlyBoarding || inst.metadata.isBoarding;
      return matchesRegion && matchesSearch && matchesType && matchesGender && matchesBoarding && inst.status === 'published';
    });
  }, [institutions, region, searchTerm, selectedType, selectedGender, onlyBoarding]);

  const fetchSmartInsight = async () => {
    if (searchTerm.length < 4) return;
    setIsInsightLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Analyze the query "${searchTerm}" within the context of Eswatini education. Provide a strategic summary and list related institution types found in the Kingdom.`,
        config: { tools: [{ googleSearch: {} }] },
      });
      const text = response.text || "";
      const links = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
      setSmartInsight({ text, links });
    } catch (e) {
      console.error(e);
    } finally {
      setIsInsightLoading(false);
    }
  };

  useEffect(() => {
    const timer = setTimeout(() => {
      if (searchTerm) fetchSmartInsight();
    }, 1500);
    return () => clearTimeout(timer);
