import React, { useState } from 'react';
import { Institution, User, Region, InstitutionType, GenderType } from '../types';
import { GoogleGenAI } from "@google/genai";

interface InstitutionAdminDashboardProps {
  user: User;
  institutions: Institution[];
  onUpdate: (inst: Institution) => void;
  onAdd: (inst: Institution) => void;
}

const InstitutionAdminDashboard: React.FC<InstitutionAdminDashboardProps> = ({ user, institutions, onUpdate, onAdd }) => {
  const [editingId, setEditingId] = useState<string | null>(user.institutionId || null);
  const inst = institutions.find(i => i.id === editingId);
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [activeTab, setActiveTab] = useState<'content' | 'verification' | 'analytics'>('content');

  const [isCreating, setIsCreating] = useState(!user.institutionId && !editingId);
  const [formData, setFormData] = useState<Partial<Institution>>({
    name: '',
    region: Region.HHOHHO,
    type: [InstitutionType.HIGH_SCHOOL],
    status: 'pending',
    trustScore: 0,
    metadata: {
      gender: GenderType.MIXED,
      isBoarding: true,
      feeRange: { min: 0, max: 0 },
      establishedYear: new Date().getFullYear(),
      studentCount: 0
    },
    contact: { address: '', phone: '', email: '' },
    documents: [],
    sections: {
      homepage: { title: 'Welcome', content: '', enabled: true },
      about: { title: 'About Us', content: '', enabled: true },
      admissions: { title: 'Admissions', content: '', enabled: true },
      academics: { title: 'Academics', content: '', enabled: true },
      studentLife: { title: 'Student Life', content: '', enabled: false },
      news: { title: 'News', content: '', enabled: false },
      contact: { title: 'Contact Us', content: '', enabled: true }
    },
    stats: { views: 0, applications: 0, engagementRate: 0 }
  });

  const handleCreate = (e: React.FormEvent) => {
    e.preventDefault();
    const newId = `inst-${Date.now()}`;
    const newInst: Institution = {
      ...(formData as any),
      id: newId,
      slug: (formData.name || '').toLowerCase().replace(/\s+/g, '-'),
      logo: 'https://picsum.photos/seed/newschool/200/200',
      coverImage: 'https://picsum.photos/seed/newschoolcover/1200/400',
      adminId: user.id
    };
    onAdd(newInst);
    setIsCreating(false);
    setEditingId(newId);
  };

  const handleSectionUpdate = (key: keyof typeof inst.sections, field: 'content' | 'enabled' | 'title', value: any) => {
    if (!inst) return;
    const updated = {
      ...inst,
      sections: {
        ...inst.sections,
        [key]: { ...inst.sections[key], [field]: value }
      }
    };
    onUpdate(updated);
  };

  const handleAiAssist = async (key: keyof typeof inst.sections) => {
    if (!inst) return;
    setIsAiLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Write a professional ${inst.sections[key].title} for ${inst.name} in Eswatini. Focus on its values as a ${inst.type.join(' ')} institution. Use a tone suitable for parents and prospective students.`;
      const response = await ai.models.generateContent({ model: 'gemini-3-flash-preview', contents: prompt });
      handleSectionUpdate(key, 'content', response.text?.trim() || "AI generation failed.");
    } catch (error) {
      console.error(error);
      alert("AI offline.");
    } finally { setIsAiLoading(false); }
  };

  if (isCreating) {
    return (
      <div className="max-w-4xl mx-auto px-4 py-24">
        <div className="bg-white p-12 rounded-[48px] shadow-2xl border border-slate-100">
          <h1 className="text-4xl font-black text-slate-900 mb-4">Establish Your Digital Presence</h1>
          <p className="text-slate-500 mb-12 font-medium">Create your school portal and reach thousands of prospective students across Eswatini.</p>
          <form onSubmit={handleCreate} className="space-y-8">
             <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div>
                   <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">School Name</label>
                   <input required type="text" className="w-full bg-slate-50 border-none rounded-2xl px-6 py-4 focus:ring-4 focus:ring-blue-100 font-bold" placeholder="Mbabane High School" value={formData.name} onChange={e => setFormData({ ...formData, name: e.target.value })} />
                </div>
                <div>
                   <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-2">Region</label>
                   <select className="w-full bg-slate-50 border-none rounded-2xl px-6 py-4 focus:ring-4 focus:ring-blue-100 font-bold" value={formData.region} onChange={e => setFormData({ ...formData, region: e.target.value as Region })}>
                      {Object.values(Region).map(r => <option key={r} value={r}>{r}</option>)}
                   </select>
                </div>
             </div>
             <button type="submit" className="w-full bg-slate-900 text-white font-black py-6 rounded-3xl shadow-xl shadow-slate-200 hover:bg-blue-600 transition-all uppercase tracking-widest text-sm">Initialize Portal</button>
          </form>
        </div>
      </div>
    );
  }

  if (!inst) return null;

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-12 gap-6">
        <div>
          <div className="flex items-center gap-3 mb-2">
            <span className={`px-4 py-1 rounded-full text-[10px] font-black uppercase tracking-widest ${inst.status === 'published' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'}`}>{inst.status}</span>
            <span className="text-slate-400 text-xs font-bold uppercase tracking-widest">Score: {inst.trustScore}%</span>
          </div>
          <h1 className="text-4xl font-black text-slate-900 leading-tight">{inst.name}</h1>
        </div>
        <div className="flex gap-4">
           <a href={`#/school/${inst.slug}`} target="_blank" className="bg-white border border-slate-200 text-slate-700 px-8 py-4 rounded-2xl font-black uppercase tracking-widest text-xs shadow-sm hover:bg-slate-50 transition-all">Preview Site</a>
