               </div>
               <div className="bg-blue-50 p-8 rounded-3xl">
                  <h4 className="text-sm font-black text-blue-900 mb-2 uppercase tracking-widest">Verification Status</h4>
                  <div className="flex items-center gap-4">
                     <div className="w-3 h-3 bg-amber-500 rounded-full animate-pulse"></div>
                     <p className="text-blue-800 font-bold text-sm">Awaiting manual review of documents. Estimated time: 24-48h.</p>
