import React, { useState, useMemo, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { Institution, Region, InstitutionType, GenderType } from '../types';
import { GoogleGenAI } from "@google/genai";

interface BrowsePageProps {
  institutions: Institution[];
  region: Region | null;
  onSelectRegion: (region: Region) => void;
  favorites: string[];
  onToggleFavorite: (id: string) => void;
}

const BrowsePage: React.FC<BrowsePageProps> = ({ institutions, region, onSelectRegion, favorites, onToggleFavorite }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedType, setSelectedType] = useState<string>('All');
  const [selectedGender, setSelectedGender] = useState<string>('All');
  const [onlyBoarding, setOnlyBoarding] = useState(false);
  const [aiRecommendation, setAiRecommendation] = useState<string | null>(null);
  const [isAiSearching, setIsAiSearching] = useState(false);
  const [showFilters, setShowFilters] = useState(false);

  const filteredInstitutions = useMemo(() => {
    return institutions.filter(inst => {
      const matchesRegion = region ? inst.region === region : true;
      const matchesSearch = inst.name.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesType = selectedType === 'All' || inst.type.some(t => t === selectedType);
      const matchesGender = selectedGender === 'All' || inst.metadata.gender === selectedGender;
      const matchesBoarding = !onlyBoarding || inst.metadata.isBoarding;
      return matchesRegion && matchesSearch && matchesType && matchesGender && matchesBoarding && inst.status === 'published';
    });
  }, [institutions, region, searchTerm, selectedType, selectedGender, onlyBoarding]);

  const handleAiSearch = async () => {
    if (!searchTerm || searchTerm.length < 10) return;
    setIsAiSearching(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Based on this search: "${searchTerm}", which types of schools in Eswatini would you recommend? Provide a concise, high-level recommendation for the user. Mention specific regions if applicable.`,
      });
      setAiRecommendation(response.text || null);
    } catch (e) {
      console.error(e);
    } finally {
      setIsAiSearching(false);
    }
  };

  const allTypes = ['All', ...Object.values(InstitutionType)];
  const allGenders = ['All', ...Object.values(GenderType)];

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
      <div className="flex flex-col md:flex-row md:items-end justify-between mb-12 gap-4">
        <div>
          <h1 className="text-4xl font-black text-slate-900 mb-2">Education Directory</h1>
          <p className="text-slate-500 font-medium italic">Powered by AI Discovery & Verified Listings</p>
        </div>
        <button 
          onClick={() => setShowFilters(!showFilters)}
          className="md:hidden bg-white border border-slate-200 px-6 py-3 rounded-2xl text-slate-700 font-bold flex items-center justify-center"
        >
          Filters
        </button>
      </div>

      <div className="flex flex-col lg:flex-row gap-10">
        <aside className={`w-full lg:w-72 space-y-10 ${showFilters ? 'block' : 'hidden lg:block'}`}>
          <div className="bg-white rounded-[32px] p-8 border border-slate-100 shadow-sm space-y-8">
            <div>
              <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-4">Region</label>
              <div className="space-y-2">
                {Object.values(Region).map(r => (
                  <button key={r} onClick={() => onSelectRegion(r)} className={`w-full px-4 py-2.5 text-left text-sm font-bold rounded-xl transition-all ${region === r ? 'bg-blue-600 text-white shadow-lg' : 'bg-slate-50 text-slate-600 hover:bg-slate-100'}`}>{r}</button>
                ))}
              </div>
            </div>

            <div>
              <label className="block text-xs font-black text-slate-400 uppercase tracking-widest mb-4">Gender</label>
              <div className="grid grid-cols-1 gap-2">
                {allGenders.map(g => (
                  <button key={g} onClick={() => setSelectedGender(g)} className={`px-4 py-2.5 text-left text-sm font-bold rounded-xl transition-all ${selectedGender === g ? 'bg-indigo-600 text-white shadow-lg' : 'bg-slate-50 text-slate-600 hover:bg-slate-100'}`}>{g}</button>
                ))}
              </div>
            </div>

            <div className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl">
              <span className="text-sm font-bold text-slate-700">Boarding Only</span>
              <button onClick={() => setOnlyBoarding(!onlyBoarding)} className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${onlyBoarding ? 'bg-emerald-500' : 'bg-slate-300'}`}>
                <span className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${onlyBoarding ? 'translate-x-6' : 'translate-x-1'}`} />
              </button>
            </div>
          </div>
        </aside>

        <div className="flex-1">
          <div className="mb-8 relative group">
            <input
              type="text"
              placeholder="E.g. I need a private boarding school for girls in Hhohho..."
              className="block w-full pl-14 pr-24 py-6 bg-white border border-slate-200 rounded-3xl focus:ring-4 focus:ring-blue-100 focus:border-blue-500 shadow-sm transition-all text-lg font-medium"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleAiSearch()}
            />
            <div className="absolute inset-y-0 left-5 flex items-center pointer-events-none text-slate-400">
               <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
            </div>
            <button 
              onClick={handleAiSearch}
              disabled={isAiSearching || searchTerm.length < 5}
              className="absolute right-4 top-1/2 -translate-y-1/2 bg-blue-600 text-white px-4 py-2 rounded-2xl text-xs font-black uppercase tracking-widest disabled:opacity-50 transition-all hover:bg-blue-700 shadow-lg shadow-blue-200"
            >
              {isAiSearching ? 'Thinking...' : 'AI Recommend'}
            </button>
          </div>

          {aiRecommendation && (
            <div className="mb-10 p-8 bg-gradient-to-br from-indigo-50 to-blue-50 rounded-[40px] border border-blue-100 animate-in fade-in slide-in-from-top-4">
              <div className="flex items-center gap-3 mb-4">
                 <div className="w-8 h-8 bg-blue-600 text-white rounded-xl flex items-center justify-center shadow-lg"><svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path d="M11 3a1 1 0 10-2 0v1a1 1 0 102 0V3zM5.884 6.98a1 1 0 10-1.414-1.414l-.707.707a1 1 0 101.414 1.414l.707-.707zm11.312 0l.707-.707a1 1 0 10-1.414-1.414l-.707.707a1 1 0 101.414 1.414zM5 11a1 1 0 100-2H4a1 1 0 100 2h1zm11 0a1 1 0 100-2h-1a1 1 0 100 2h1zM8.99 14a1 1 0 100 2h1a1 1 0 100-2h-1zM5.884 13.02l-.707.707a1 1 0 101.414 1.414l.707-.707a1 1 0 10-1.414-1.414zm11.312 0l-.707.707a1 1 0 101.414-1.414l.707-.707a1 1 0 10-1.414 1.414z" /></svg></div>
                 <h3 className="text-lg font-black text-blue-900">Smart Recommendation</h3>
              </div>
              <p className="text-blue-800 leading-relaxed font-medium">{aiRecommendation}</p>
            </div>
          )}

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            {filteredInstitutions.map(inst => (
              <div key={inst.id} className="bg-white rounded-[32px] overflow-hidden border border-slate-100 shadow-sm hover:shadow-2xl transition-all group relative flex flex-col">
                <button onClick={() => onToggleFavorite(inst.id)} className={`absolute top-6 left-6 z-10 p-3 rounded-full backdrop-blur-md shadow-lg transition-all ${favorites.includes(inst.id) ? 'bg-rose-500 text-white' : 'bg-white/70 text-slate-700 hover:bg-white'}`}>
                  <svg className="w-5 h-5" fill={favorites.includes(inst.id) ? "currentColor" : "none"} viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z" /></svg>
                </button>
                <Link to={`/school/${inst.slug}`} className="block relative h-56">
                  <img src={inst.coverImage} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700" />
                  <div className="absolute top-6 right-6 z-10 bg-slate-900/80 backdrop-blur-md px-4 py-1.5 rounded-full text-[10px] font-black text-white uppercase tracking-widest">{inst.region}</div>
                </Link>
                <div className="p-8 flex-grow flex flex-col">
                  <div className="flex justify-between items-start mb-4">
                    <Link to={`/school/${inst.slug}`} className="flex-1">
                      <h3 className="text-2xl font-black text-slate-900 leading-tight group-hover:text-blue-600 transition-colors">
                        {inst.name}
                        {inst.isVerified && <span className="ml-2 text-blue-500 inline-block">✔</span>}
                      </h3>
                    </Link>
                    <img src={inst.logo} className="w-12 h-12 rounded-2xl object-contain border bg-white ml-4 shrink-0" />
                  </div>
                  <div className="flex flex-wrap gap-2 mb-6">
                    <span className="px-3 py-1 bg-blue-50 text-blue-700 rounded-full text-[10px] font-black uppercase tracking-widest">{inst.metadata.gender}</span>
                    <span className="px-3 py-1 bg-slate-100 text-slate-600 rounded-full text-[10px] font-black uppercase tracking-widest">Est. {inst.metadata.establishedYear}</span>
                  </div>
                  <div className="mt-auto flex items-center justify-between">
                    <p className="text-sm font-bold text-slate-900">SZL {inst.metadata.feeRange.min.toLocaleString()} - {inst.metadata.feeRange.max.toLocaleString()}</p>
                    <Link to={`/school/${inst.slug}`} className="bg-slate-900 text-white px-5 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest">Profile</Link>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

