import React, { useState } from 'react';
import { Institution, User, Region, InstitutionType, GenderType, Review, Message, Alumnus } from '../types';
import { GoogleGenAI } from "@google/genai";

interface InstitutionAdminDashboardProps {
  user: User;
  institutions: Institution[];
  onUpdate: (inst: Institution) => void;
  onAdd: (inst: Institution) => void;
}

const InstitutionAdminDashboard: React.FC<InstitutionAdminDashboardProps> = ({ user, institutions, onUpdate, onAdd }) => {
  const [editingId, setEditingId] = useState<string | null>(user.institutionId || null);
  const inst = institutions.find(i => i.id === editingId);
  const [activeTab, setActiveTab] = useState<'content' | 'theme' | 'academic' | 'finance' | 'verification' | 'messages' | 'reviews' | 'alumni'>('content');
  const [isAiLoading, setIsAiLoading] = useState(false);

  if (!inst) return <div className="p-20 text-center font-black text-slate-400">Loading portal...</div>;

  const handleUpdate = (field: string, value: any) => {
    onUpdate({ ...inst, [field]: value });
  };

  const handleThemeUpdate = (field: string, value: any) => {
    onUpdate({ ...inst, theme: { ...inst.theme, [field]: value } });
  };

  const handleSubdomainUpdate = (val: string) => {
    handleUpdate('subdomain', val.toLowerCase().replace(/[^a-z0-9]/g, ''));
  };

  const handleAiAssist = async (sectionKey: string) => {
    setIsAiLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `Write a high-quality, professional ${inst.sections[sectionKey].title} section for ${inst.name}, an institution in Eswatini. Focus on education excellence and community. Use a modern academic tone. Max 150 words.`;
      const response = await ai.models.generateContent({ model: 'gemini-3-flash-preview', contents: prompt });
      const updatedSections = { ...inst.sections };
      updatedSections[sectionKey].content = response.text?.trim() || "Draft failed.";
      handleUpdate('sections', updatedSections);
    } catch (e) {
      console.error(e);
    } finally {
      setIsAiLoading(false);
    }
  };

  const sidebarTabs = [
    { id: 'content', label: 'Site Builder', icon: '🎨' },
    { id: 'theme', label: 'Theme & Fonts', icon: '✨' },
    { id: 'academic', label: 'Academic Tools', icon: '📚' },
    { id: 'finance', label: 'Finance & Fees', icon: '💳' },
    { id: 'messages', label: 'Inbox', icon: '📩', badge: inst.messages.filter(m => !m.isRead).length },
    { id: 'reviews', label: 'Reviews', icon: '⭐' },
    { id: 'alumni', label: 'Alumni', icon: '🎓' },
    { id: 'verification', label: 'Trust & Verification', icon: '🛡️' }
  ];

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-12">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-12 gap-6">
        <div>
          <h1 className="text-4xl font-black text-slate-900 leading-tight">{inst.name}</h1>
          <div className="flex items-center gap-3 mt-1">
             <span className="text-slate-500 font-bold text-xs uppercase tracking-widest">{inst.subdomain ? `${inst.subdomain}.schoolsswz.com` : 'Subdomain not set'}</span>
             {inst.isVerified && <span className="bg-blue-100 text-blue-600 px-2 py-0.5 rounded-full text-[10px] font-black uppercase tracking-widest">Verified Portal</span>}
          </div>
        </div>
        <div className="flex gap-4">
           <a href={`#/school/${inst.slug}`} target="_blank" className="bg-white border px-8 py-4 rounded-2xl font-black uppercase tracking-widest text-xs shadow-sm hover:shadow-md transition-all">Preview Portal</a>
           <button className="bg-blue-600 text-white px-8 py-4 rounded-2xl font-black uppercase tracking-widest text-xs shadow-xl shadow-blue-200 hover:bg-blue-700 transition-all">Update & Publish</button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-12">
        <aside className="lg:col-span-1 space-y-2">
          {sidebarTabs.map(tab => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
