            <div className="w-48 h-48 bg-white p-6 shadow-[0_32px_64px_-16px_rgba(0,0,0,0.3)] border-4 border-white shrink-0 mb-[-120px] md:mb-[-150px] z-10" style={{ borderRadius: themeStyle['--radius' as any] }}>
              <img src={inst.logo} className="w-full h-full object-contain" />
            </div>
            <div className="flex-1 pb-4">
               <div className="flex items-center gap-3 mb-2">
                  <span className="text-[10px] font-black text-white/60 uppercase tracking-widest">{inst.region} Region</span>
                  {inst.isVerified && <span className="bg-blue-500 text-white px-2 py-0.5 rounded-full text-[8px] font-black uppercase tracking-widest shadow-lg">Verified Institution</span>}
