            <div className="flex gap-4 pb-4">
               <button onClick={() => onToggleFavorite(inst.id)} className={`p-5 rounded-3xl backdrop-blur-md transition-all ${favorites.includes(inst.id) ? 'bg-rose-500 text-white' : 'bg-white/10 text-white hover:bg-white/20 border border-white/20'}`}>
                  <svg className="w-6 h-6" fill={favorites.includes(inst.id) ? "currentColor" : "none"} viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z" /></svg>
               </button>
               <button className="bg-white text-slate-900 px-10 py-5 rounded-[24px] font-black uppercase tracking-widest text-[10px] shadow-2xl hover:scale-105 transition-all">Enroll Now</button>
            </div>
          </div>
        </div>
      </div>

      {/* Modern Navigation */}
