interface InstitutionAdminDashboardProps {
  user: User;
  institutions: Institution[];
  onUpdate: (inst: Institution) => void;
  onAdd: (inst: Institution) => void;
}

const InstitutionAdminDashboard: React.FC<InstitutionAdminDashboardProps> = ({ user, institutions, onUpdate, onAdd }) => {
  const inst = institutions.find(i => i.id === (user.institutionId || institutions.find(i => i.adminId === user.id)?.id));
  const [activeTab, setActiveTab] = useState<'content' | 'theme' | 'messages' | 'reviews' | 'alumni' | 'finance'>('content');
  const [isAiLoading, setIsAiLoading] = useState(false);

  if (!inst) return <div className="p-24 text-center font-black text-slate-300 uppercase tracking-widest">Portal initializing...</div>;

  const handleUpdate = (field: string, value: any) => onUpdate({ ...inst, [field]: value });

  const handleReviewAction = (revId: string, status: 'approved' | 'spam') => {
    const updated = inst.reviews.map(r => r.id === revId ? { ...r, status, isModerated: true } : r);
    handleUpdate('reviews', updated);
  };

  const handleMessageRead = (msgId: string) => {
    const updated = inst.messages.map(m => m.id === msgId ? { ...m, isRead: true } : m);
    handleUpdate('messages', updated);
  };

  const tabs = [
    { id: 'content', label: 'Site Builder', icon: '🎨' },
    { id: 'messages', label: 'Inbox', icon: '📩', count: inst.messages.filter(m => !m.isRead).length },
    { id: 'reviews', label: 'Moderation', icon: '⭐', count: inst.reviews.filter(r => r.status === 'pending').length },
    { id: 'alumni', label: 'Alumni Network', icon: '🎓' },
    { id: 'finance', label: 'Financials', icon: '💳' },
    { id: 'theme', label: 'Identity', icon: '✨' }
  ];

  return (
    <div className="max-w-7xl mx-auto px-6 md:px-8 py-12">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-16 gap-8">
        <div>
          <h1 className="text-4xl font-black text-slate-900 tracking-tight">{inst.name}</h1>
          <p className="text-slate-400 font-bold uppercase tracking-widest text-[10px] mt-1">Institutional Administration Dashboard</p>
        </div>
        <div className="flex gap-4">
           <a href={`#/school/${inst.slug}`} target="_blank" className="bg-white border border-slate-200 px-8 py-4 rounded-3xl font-black uppercase tracking-widest text-[10px] shadow-sm hover:shadow-md transition-all">Visit Public Site</a>
