                <div className="space-y-12 divide-y divide-slate-50">
                  {Object.keys(inst.sections).map(key => (
                    <div key={key} className="pt-12 first:pt-0">
                       <div className="flex justify-between items-center mb-6">
                          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Component: {inst.sections[key].title}</span>
                          <button disabled={isAiLoading} onClick={() => {}} className="text-blue-600 text-[10px] font-black uppercase tracking-widest flex items-center gap-2 hover:underline">
                             <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
                             AI Optimize Draft
