import React, { useState, useMemo } from 'react';
import { Link } from 'react-router-dom';
import { Institution, Region, InstitutionType, GenderType, SubscriptionPlan } from '../types';

interface BrowsePageProps {
  institutions: Institution[];
  region: Region | null;
  onSelectRegion: (region: Region) => void;
  favorites: string[];
  onToggleFavorite: (id: string) => void;
}

const BrowsePage: React.FC<BrowsePageProps> = ({ institutions, region, onSelectRegion, favorites, onToggleFavorite }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedType, setSelectedType] = useState<string>('All');

  const filteredInstitutions = useMemo(() => {
    return institutions
      .filter(inst => {
        const matchesRegion = region ? inst.region === region : true;
        const matchesSearch = inst.name.toLowerCase().includes(searchTerm.toLowerCase());
        const matchesType = selectedType === 'All' || inst.type.some(t => t === selectedType);
        return matchesRegion && matchesSearch && matchesType && inst.status === 'published';
      })
      .sort((a, b) => {
        // Featured/Enterprise listings come first
        if (a.isFeatured && !b.isFeatured) return -1;
        if (!a.isFeatured && b.isFeatured) return 1;
        return 0;
      });
  }, [institutions, region, searchTerm, selectedType]);

  return (
    <div className="max-w-7xl mx-auto px-6 lg:px-8 py-12">
      <div className="flex flex-col md:flex-row justify-between items-end mb-12 gap-6">
        <div>
          <h1 className="text-5xl font-black text-slate-900 tracking-tighter">Discover Eswatini</h1>
          <p className="text-slate-500 font-bold uppercase tracking-widest text-[10px] mt-2">Verified & Featured Institutions</p>
        </div>
        <div className="flex bg-white p-2 rounded-2xl shadow-sm border">
           {Object.values(Region).map(r => (
             <button key={r} onClick={() => onSelectRegion(r)} className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${region === r ? 'bg-slate-900 text-white shadow-xl' : 'text-slate-400 hover:text-slate-600'}`}>{r}</button>
           ))}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10">
        {filteredInstitutions.map(inst => (
          <div key={inst.id} className={`bg-white rounded-[40px] overflow-hidden border transition-all hover:shadow-2xl flex flex-col group relative ${inst.isFeatured ? 'border-blue-200 ring-1 ring-blue-50 shadow-lg shadow-blue-50' : 'border-slate-100'}`}>
            {inst.isFeatured && (
               <div className="absolute top-6 left-6 z-20 bg-blue-600 text-white px-3 py-1.5 rounded-full text-[8px] font-black uppercase tracking-widest shadow-xl flex items-center gap-2">
                 <svg className="w-3 h-3" fill="currentColor" viewBox="0 0 20 20"><path d="M9.049 2.927c.3-.921 1.603-.921 1.902 0l1.07 3.292a1 1 0 00.95.69h3.462c.969 0 1.371 1.24.588 1.81l-2.8 2.034a1 1 0 00-.364 1.118l1.07 3.292c.3.921-.755 1.688-1.54 1.118l-2.8-2.034a1 1 0 00-1.175 0l-2.8 2.034c-.784.57-1.838-.197-1.539-1.118l1.07-3.292a1 1 0 00-.364-1.118L2.98 8.72c-.783-.57-.38-1.81.588-1.81h3.461a1 1 0 00.951-.69l1.07-3.292z" /></svg>
                 Featured School
               </div>
            )}
            <Link to={`/school/${inst.slug}`} className="block relative h-64">
              <img src={inst.coverImage} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-1000" loading="lazy" />
              <div className="absolute inset-0 bg-gradient-to-t from-black/50 to-transparent" />
              <div className="absolute bottom-6 right-6 bg-white p-3 rounded-2xl shadow-xl">
                 <img src={inst.logo} className="w-10 h-10 object-contain" />
              </div>
            </Link>
            <div className="p-10 flex-grow flex flex-col">
              <h3 className="text-2xl font-black text-slate-900 group-hover:text-blue-600 transition-colors mb-2">{inst.name}</h3>
              <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mb-6">{inst.region}</p>

              <div className="flex gap-2 mb-8">
                 {inst.type.map(t => (
                   <span key={t} className="bg-slate-50 px-3 py-1 rounded-full text-[8px] font-black uppercase tracking-widest text-slate-500 border border-slate-100">{t}</span>
                 ))}
              </div>

              <div className="mt-auto flex justify-between items-center">
                 <div className="flex flex-col">
                    <span className="text-[10px] font-black text-slate-300 uppercase tracking-widest">Trust Score</span>
                    <span className="text-lg font-black text-emerald-500">{inst.trustScore}%</span>
                 </div>
                 <Link to={`/school/${inst.slug}`} className="bg-slate-900 text-white px-6 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl shadow-slate-200 hover:bg-blue-600 transition-all">Explore Portal</Link>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

