                        </div>
                        <div className="p-8 bg-slate-50 rounded-3xl border border-slate-100">
                           <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-6">Principal's Address</h4>
                           <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
                              <div>
                                 <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Principal Name</label>
                                 <input className="w-full bg-white border-none rounded-xl px-4 py-3 font-bold" value={inst.sections.homepage.principalMessage.name} onChange={e => updateSectionField('homepage', 'principalMessage', {...inst.sections.homepage.principalMessage, name: e.target.value})} />
                              </div>
                              <div>
                                 <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Photo URL</label>
                                 <input className="w-full bg-white border-none rounded-xl px-4 py-3 font-bold" value={inst.sections.homepage.principalMessage.photo} onChange={e => updateSectionField('homepage', 'principalMessage', {...inst.sections.homepage.principalMessage, photo: e.target.value})} />
                              </div>
                           </div>
                           <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Message Content</label>
                           <textarea rows={6} className="w-full bg-white border-none rounded-xl px-4 py-3 font-medium" value={inst.sections.homepage.principalMessage.text} onChange={e => updateSectionField('homepage', 'principalMessage', {...inst.sections.homepage.principalMessage, text: e.target.value})} />
                        </div>
                     </div>
                   )}

                   {activeSectionTab === 'admissions' && (
                     <div className="space-y-10">
                        <div className="flex items-center justify-between p-6 bg-blue-50 rounded-3xl">
                           <div>
                              <h4 className="font-black text-slate-900 uppercase tracking-widest text-[10px] mb-1">Online Application System</h4>
                              <p className="text-[10px] text-blue-600 font-bold">Enable prospective students to apply directly through your page.</p>
                           </div>
                           <button onClick={() => updateSectionField('admissions', 'allowOnlineApplications', !inst.sections.admissions.allowOnlineApplications)} className={`w-14 h-8 rounded-full flex items-center px-1 transition-colors ${inst.sections.admissions.allowOnlineApplications ? 'bg-blue-600' : 'bg-slate-300'}`}>
                              <div className={`w-6 h-6 bg-white rounded-full shadow-sm transition-transform ${inst.sections.admissions.allowOnlineApplications ? 'translate-x-6' : 'translate-x-0'}`} />
                           </button>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                           <div>
                              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Entry Requirements</label>
                              <textarea rows={6} className="w-full bg-slate-50 border-none rounded-2xl px-6 py-4 font-medium" value={inst.sections.admissions.requirements} onChange={e => updateSectionField('admissions', 'requirements', e.target.value)} />
                           </div>
                           <div>
                              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Fees Structure (Summary)</label>
                              <textarea rows={6} className="w-full bg-slate-50 border-none rounded-2xl px-6 py-4 font-medium" value={inst.sections.admissions.fees} onChange={e => updateSectionField('admissions', 'fees', e.target.value)} />
                           </div>
                        </div>
                     </div>
                   )}

                   {activeSectionTab === 'academics' && (
                      <div className="space-y-10">
                         <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Program Registry</h4>
                         <div className="space-y-4">
                            {inst.sections.academics.programs.map((p, idx) => (
                              <div key={p.id} className="p-6 bg-slate-50 rounded-2xl border border-slate-100 flex items-center justify-between group">
                                 <div>
                                    <p className="font-black text-slate-900 uppercase tracking-widest text-[10px]">{p.name}</p>
                                    <p className="text-[10px] text-slate-400 font-bold">{p.duration}</p>
                                 </div>
                                 <button className="text-slate-300 group-hover:text-rose-500 transition-colors">🗑️</button>
                              </div>
                            ))}
                            <button className="w-full py-4 border-2 border-dashed border-slate-200 rounded-2xl text-[10px] font-black uppercase tracking-widest text-slate-300 hover:bg-slate-50 transition-all">+ Add New Program</button>
                         </div>
                      </div>
                   )}
                </div>
              </div>
            )}
         </div>
      </div>
    </div>
  );
};

