import React, { useState } from 'react';
import { useParams, Navigate } from 'react-router-dom';
import { Institution } from '../types';

interface InstitutionProfileProps {
  institutions: Institution[];
  favorites: string[];
  onToggleFavorite: (id: string) => void;
  lang: 'en' | 'ss';
}

const InstitutionProfile: React.FC<InstitutionProfileProps> = ({ institutions, favorites, onToggleFavorite, lang }) => {
  const { slug } = useParams<{ slug: string }>();
  const inst = institutions.find(i => i.slug === slug);
  const [activeSection, setActiveSection] = useState<string>('homepage');

  if (!inst) return <Navigate to="/browse" />;

  const themeStyle = {
    '--primary': inst.theme.primaryColor,
    '--radius': inst.theme.borderRadius === 'none' ? '0' : inst.theme.borderRadius === 'md' ? '12px' : inst.theme.borderRadius === '2xl' ? '40px' : '9999px',
    'fontFamily': inst.theme.fontFamily === 'Inter' ? 'Inter, sans-serif' : inst.theme.fontFamily === 'Serif' ? 'Georgia, serif' : 'monospace'
  } as React.CSSProperties;

  return (
    <div className="min-h-screen bg-slate-50" style={themeStyle}>
      <div className="relative h-[400px] md:h-[500px] overflow-hidden">
        <img src={inst.coverImage} className="w-full h-full object-cover" loading="lazy" />
        <div className="absolute inset-0 bg-gradient-to-t from-slate-900 via-slate-900/40 to-transparent" />
        <div className="absolute bottom-0 left-0 w-full p-8 md:p-12">
          <div className="max-w-7xl mx-auto flex flex-col md:flex-row items-end gap-10">
            <div className="w-40 h-40 bg-white p-5 shadow-2xl shrink-0 mb-[-80px] md:mb-[-120px] z-10 overflow-hidden" style={{ borderRadius: themeStyle['--radius' as any] }}>
              <img src={inst.logo} className="w-full h-full object-contain" />
            </div>
            <div className="flex-1 pb-2">
               <div className="flex items-center gap-3 mb-2 flex-wrap">
                  <span className="text-[10px] font-black text-white/70 uppercase tracking-widest">{inst.region} Region</span>
                  {inst.isAccredited && (
                    <span className="bg-emerald-500 text-white px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest shadow-lg flex items-center gap-2">
                      🏛 MoET Accredited: {inst.moetRegistration}
                    </span>
                  )}
               </div>
               <h1 className="text-4xl md:text-6xl font-black text-white tracking-tighter leading-none mb-4">{inst.name}</h1>
            </div>
          </div>
        </div>
      </div>

      <div className="bg-white border-b sticky top-16 z-40 overflow-x-auto shadow-sm">
        <div className="max-w-7xl mx-auto px-8 md:px-12 flex space-x-12 h-24 items-center">
           <div className="w-40 shrink-0 hidden md:block" />
           {Object.keys(inst.sections).map(key => (
             <button 
               key={key} 
               onClick={() => setActiveSection(key)} 
               className={`text-[10px] font-black uppercase tracking-widest border-b-4 h-full flex items-center px-1 whitespace-nowrap transition-all ${activeSection === key ? 'text-slate-900' : 'text-slate-400 hover:text-slate-600'}`} 
               style={{ borderBottomColor: activeSection === key ? inst.theme.primaryColor : 'transparent' }}
             >
               {key.charAt(0).toUpperCase() + key.slice(1)}
             </button>
           ))}
           <button onClick={() => setActiveSection('performance')} className={`text-[10px] font-black uppercase tracking-widest border-b-4 h-full flex items-center px-1 whitespace-nowrap ${activeSection === 'performance' ? 'text-slate-900' : 'text-slate-400'}`} style={{ borderBottomColor: activeSection === 'performance' ? inst.theme.primaryColor : 'transparent' }}>
             Performance
           </button>
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-8 md:px-12 py-24 md:py-32 grid grid-cols-1 lg:grid-cols-3 gap-16 lg:gap-24">
         <div className="lg:col-span-2 space-y-16 animate-in fade-in slide-in-from-bottom-6 duration-700">
