                         <img src={inst.sections.homepage.principalMessage.photo} className="w-48 h-64 object-cover rounded-3xl shadow-xl shrink-0" alt="Principal" />
                       )}
                       <div className="space-y-6">
                          <p className="text-xl text-slate-600 leading-relaxed italic">"{inst.sections.homepage.principalMessage.text}"</p>
                          <p className="font-black text-slate-900 uppercase tracking-widest text-xs">— {inst.sections.homepage.principalMessage.name}, Head of Institution</p>
                       </div>
                    </div>
                 </div>

                 <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    <div className="p-8 bg-white border border-slate-100 shadow-sm rounded-3xl">
                       <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-6">Latest Announcements</h3>
