                       </div>
                    </div>
                    <div className="p-8 bg-slate-900 text-white rounded-3xl">
                       <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-6">Quick Portal Links</h3>
                       <div className="grid grid-cols-1 gap-4">
                          {inst.sections.homepage.quickLinks.map((link, i) => (
                            <a key={i} href={link.url} className="w-full py-4 px-6 bg-white/5 border border-white/10 rounded-2xl flex justify-between items-center group hover:bg-white/10 transition-all">
                               <span className="text-[10px] font-black uppercase tracking-widest">{link.label}</span>
