                    <p className="text-blue-100 text-lg mb-10 leading-relaxed">{inst.sections.admissions.requirements}</p>
                    {inst.sections.admissions.allowOnlineApplications && (
                      <button className="bg-white text-blue-600 px-10 py-5 rounded-[24px] font-black uppercase tracking-widest text-[10px] shadow-xl hover:scale-105 transition-all">Open Online Application</button>
