                 </div>

                 <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
                    <div className="space-y-6">
                       <h3 className="text-2xl font-black text-slate-900">Application Process</h3>
                       <p className="text-slate-600 text-sm leading-relaxed">{inst.sections.admissions.process}</p>
                    </div>
                    <div className="space-y-6">
                       <h3 className="text-2xl font-black text-slate-900">Important Dates</h3>
                       <div className="space-y-4">
                          {inst.sections.admissions.importantDates.map((d, i) => (
                            <div key={i} className="flex justify-between items-center p-4 bg-white border border-slate-50 rounded-2xl shadow-sm">
                               <span className="text-xs font-black text-slate-900 uppercase tracking-widest">{d.event}</span>
                               <span className="text-xs font-bold text-blue-600">{d.date}</span>
                            </div>
                          ))}
                       </div>
                    </div>
                 </div>
              </div>
            )}

            {activeSection === 'academics' && (
              <div className="space-y-16">
                 <h2 className="text-4xl font-black text-slate-900 tracking-tight">Academic Catalog</h2>
                 <div className="grid grid-cols-1 gap-8">
                    {inst.sections.academics.programs.map(prog => (
                      <div key={prog.id} className="p-10 bg-white border border-slate-100 shadow-sm rounded-[40px] group hover:shadow-xl transition-all">
                         <div className="flex justify-between items-start mb-6">
                            <h4 className="text-2xl font-black text-slate-900">{prog.name}</h4>
                            <span className="bg-slate-50 px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest text-slate-400">{prog.duration}</span>
