            )}
         </div>

         <aside className="space-y-12">
            <div className="p-10 bg-white border border-slate-100 shadow-2xl sticky top-48" style={{ borderRadius: themeStyle['--radius' as any] }}>
               <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-8">Direct Contact</h3>
               <div className="space-y-8">
                  <div>
                     <p className="text-[9px] font-black text-slate-300 uppercase tracking-widest mb-2">Office Hours</p>
                     <p className="text-sm font-bold text-slate-700">{inst.contact.officeHours}</p>
                  </div>
