export default InstitutionProfile;

export enum Region {
  HHOHHO = 'Hhohho',
  MANZINI = 'Manzini',
  LUBOMBO = 'Lubombo',
  SHISELWENI = 'Shiselweni'
}

export enum InstitutionType {
  PRIMARY = 'Primary',
  HIGH_SCHOOL = 'High School',
  TERTIARY = 'Tertiary',
  PRIVATE = 'Private',
  PUBLIC = 'Public'
}

export enum SubscriptionPlan {
  FREE = 'Free',
  PREMIUM = 'Premium',
  ENTERPRISE = 'Enterprise'
}

export enum UserRole {
  SUPER_ADMIN = 'Super Admin',
  INSTITUTION_ADMIN = 'Institution Admin',
  VISITOR = 'Visitor'
}

export enum GenderType {
  BOYS = 'Boys',
  GIRLS = 'Girls',
  MIXED = 'Mixed'
}

export interface QuickLink {
  label: string;
  url: string;
}

export interface Announcement {
  id: string;
  title: string;
  date: string;
  content: string;
  isFeatured: boolean;
}

export interface StaffMember {
  id: string;
  name: string;
  role: string;
  photo?: string;
  bio?: string;
}

export interface AcademicProgram {
  id: string;
  name: string;
  duration: string;
  description: string;
}

export interface Scholarship {
  id: string;
  name: string;
  amount: string;
  criteria: string;
  deadline: string;
  applicationLink?: string;
}

export interface NationalStats {
  passRate: number;
  teacherStudentRatio: string;
  nationalRanking: number;
  lastInspectionDate: string;
}

export interface SEOMetadata {
  title: string;
  description: string;
  keywords: string[];
  healthScore: number;
}

export interface Institution {
  id: string;
  name: string;
  slug: string;
  subdomain?: string;
  logo: string;
  coverImage: string;
  region: Region;
  type: InstitutionType[];
  isVerified: boolean;
  isAccredited: boolean;
  moetRegistration: string;
  isFeatured: boolean;
  trustScore: number;
  plan: SubscriptionPlan;
  status: 'pending' | 'published' | 'suspended';
  stats_performance?: NationalStats;
  seo: SEOMetadata;
  theme: {
    primaryColor: string;
    fontFamily: string;
    borderRadius: string;
    layout: string;
  };
  metadata: {
    gender: GenderType;
    isBoarding: boolean;
    feeRange: { min: number; max: number };
    establishedYear: number;
    studentCount: number;
    hasStudentPortal: boolean;
  };
  documents: any[];
  academicTools: any[];
  transactions: any[];
  reviews: any[];
  messages: any[];
  alumni: any[];
  contact: {
    address: string;
    phone: string;
    email: string;
    website?: string;
    officeHours: string;
    googleMapsUrl?: string;
  };
  sections: {
    homepage: {
      welcomeMessage: string;
      principalMessage: {
        text: string;
        name: string;
        photo?: string;
      };
      quickLinks: QuickLink[];
      announcements: Announcement[];
    };
    about: {
      history: string;
      vision: string;
      mission: string;
      values: string[];
      leadership: StaffMember[];
    };
    admissions: {
      requirements: string;
      process: string;
      fees: string;
      scholarships: string;
      importantDates: { event: string; date: string }[];
      allowOnlineApplications: boolean;
    };
    academics: {
      programs: AcademicProgram[];
      departments: string[];
      staff: StaffMember[];
      calendarUrl?: string;
    };
    studentLife: {
      sports: string[];
      clubs: string[];
      facilities: string[];
      supportServices: string;
    };
    funding: {
      overview: string;
      scholarships: Scholarship[];
      financialAidPolicy: string;
    };
  };
  stats: {
    views: number;
    applications: number;
    engagementRate: number;
  };
  adminId: string;
}

export interface User {
  id: string;
  email: string;
  name: string;
  role: UserRole;
  institutionId?: string;
  isVerified: boolean;
  twoFactorEnabled: boolean;
}

