interface InstitutionAdminDashboardProps {
  user: User;
  institutions: Institution[];
  onUpdate: (inst: Institution) => void;
  onAdd: (inst: Institution) => void;
}

const InstitutionAdminDashboard: React.FC<InstitutionAdminDashboardProps> = ({ user, institutions, onUpdate, onAdd }) => {
  const inst = institutions.find(i => i.id === (user.institutionId || institutions.find(i => i.adminId === user.id)?.id));
  const [activeTab, setActiveTab] = useState<'identity' | 'theme' | 'sections' | 'seo' | 'plan' | 'security'>('identity');
  const [activeSectionTab, setActiveSectionTab] = useState<'homepage' | 'about' | 'admissions' | 'academics' | 'news' | 'studentLife' | 'portal'>('homepage');

  if (!inst) return <div className="p-24 text-center font-black text-slate-300">Portal starting...</div>;

  const handleUpdate = (updatedInst: Institution) => onUpdate(updatedInst);

  const updateSectionField = (section: keyof Institution['sections'], field: string, value: any) => {
    const updatedSections = {
      ...inst.sections,
      [section]: {
        ...inst.sections[section],
        [field]: value
      }
    };
    handleUpdate({ ...inst, sections: updatedSections });
  };

  const updateAboutSubField = (parent: keyof Institution['sections']['about'], field: string, value: any) => {
    const currentAbout = inst.sections.about;
    const parentVal = currentAbout[parent] as any;

    const updatedAbout = {
      ...currentAbout,
      [parent]: typeof parentVal === 'object' && !Array.isArray(parentVal) 
        ? { ...parentVal, [field]: value } 
        : value
    };

    updateSectionField('about', parent as string, updatedAbout[parent]);
  };

  const tabs = [
    { id: 'identity', label: 'Identity', icon: '🆔' },
    { id: 'theme', label: 'Appearance', icon: '✨' },
    { id: 'sections', label: 'Site Modules', icon: '🎨' },
    { id: 'seo', label: 'SEO Engine', icon: '📈' },
    { id: 'plan', label: 'Billing', icon: '💳' },
    { id: 'security', label: 'Security', icon: '🔒' }
  ];

  const sectionTabs = [
    { id: 'homepage', label: 'Homepage' },
    { id: 'about', label: 'About' },
    { id: 'admissions', label: 'Admissions' },
    { id: 'academics', label: 'Academics' },
    { id: 'news', label: 'News & Media' },
    { id: 'studentLife', label: 'Student Life' },
    { id: 'portal', label: 'Student Portal' }
  ];

  return (
    <div className="max-w-7xl mx-auto px-6 py-12">
      <div className="flex flex-col md:flex-row justify-between items-center mb-12 gap-8">
         <div className="flex items-center gap-6">
            <img src={inst.logo} className="w-20 h-20 rounded-3xl shadow-xl border p-2 bg-white object-contain" />
            <div>
               <h1 className="text-4xl font-black text-slate-900 tracking-tight">{inst.name}</h1>
               <div className="flex items-center gap-3 mt-1">
                  <span className={`px-3 py-1 rounded-full text-[8px] font-black uppercase tracking-widest ${inst.plan === SubscriptionPlan.FREE ? 'bg-slate-100' : 'bg-blue-600 text-white'}`}>{inst.plan} Plan</span>
                  <span className="text-[10px] font-bold text-slate-400">Trust Score: {inst.trustScore}%</span>
               </div>
            </div>
         </div>
         <div className="flex gap-4">
           <a href={`#/school/${inst.slug}`} target="_blank" className="bg-white border px-6 py-4 rounded-3xl font-black uppercase tracking-widest text-[10px] shadow-sm hover:bg-slate-50 transition-all">View Site</a>
           <button onClick={() => alert('Changes saved locally!')} className="bg-slate-900 text-white px-8 py-4 rounded-3xl font-black uppercase tracking-widest text-[10px] shadow-2xl hover:scale-105 transition-all">Publish Changes</button>
         </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-12">
         <aside className="lg:col-span-1 space-y-2">
            {tabs.map(t => (
               <button 
                 key={t.id} 
                 onClick={() => setActiveTab(t.id as any)}
                 className={`w-full flex items-center p-5 rounded-2xl font-black uppercase tracking-widest text-[10px] transition-all ${activeTab === t.id ? 'bg-slate-900 text-white shadow-xl' : 'text-slate-500 hover:bg-slate-100'}`}
               >
                  <span className="text-xl mr-4">{t.icon}</span>
                  {t.label}
               </button>
            ))}
         </aside>

         <div className="lg:col-span-3">
            {activeTab === 'identity' && (
              <div className="bg-white p-10 rounded-[40px] border border-slate-100 shadow-sm space-y-10 animate-in fade-in duration-500">
                <h2 className="text-2xl font-black text-slate-900">Basic Information</h2>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                   <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Institution Name</label>
                      <input className="w-full bg-slate-50 border-none rounded-2xl px-6 py-4 font-bold text-slate-900" value={inst.name} onChange={e => handleUpdate({...inst, name: e.target.value})} />
                   </div>
                   <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Region (MoET Mandatory)</label>
