export default InstitutionAdminDashboard;

import React, { useState } from 'react';
/* Removed non-existent Scholarship import from ../types */
import { Institution, User, Region, SubscriptionPlan, QuickLink, LeadershipMember, AcademicProgram, BlogPost, EventItem, CoreValue, Milestone } from '../types';

interface InstitutionAdminDashboardProps {
  user: User;
  institutions: Institution[];
  onUpdate: (inst: Institution) => void;
  onAdd: (inst: Institution) => void;
}

const InstitutionAdminDashboard: React.FC<InstitutionAdminDashboardProps> = ({ user, institutions, onUpdate, onAdd }) => {
  const inst = institutions.find(i => i.id === (user.institutionId || institutions.find(i => i.adminId === user.id)?.id));
  const [activeTab, setActiveTab] = useState<'identity' | 'theme' | 'sections' | 'seo' | 'plan' | 'security'>('identity');
  const [activeSectionTab, setActiveSectionTab] = useState<'homepage' | 'about' | 'admissions' | 'academics' | 'news' | 'studentLife' | 'portal'>('homepage');

  if (!inst) return <div className="p-24 text-center font-black text-slate-300">Portal starting...</div>;

  const handleUpdate = (updatedInst: Institution) => onUpdate(updatedInst);

  const updateSectionField = (section: keyof Institution['sections'], field: string, value: any) => {
    const updatedSections = {
      ...inst.sections,
      [section]: {
        ...inst.sections[section],
        [field]: value
      }
    };
    handleUpdate({ ...inst, sections: updatedSections });
  };

  const updateAboutSubField = (parent: keyof Institution['sections']['about'], field: string, value: any) => {
    const currentAbout = inst.sections.about;
    const parentVal = currentAbout[parent] as any;

    const updatedAbout = {
      ...currentAbout,
      [parent]: typeof parentVal === 'object' && !Array.isArray(parentVal) 
        ? { ...parentVal, [field]: value } 
        : value
    };

    updateSectionField('about', parent as string, updatedAbout[parent]);
  };

  const tabs = [
    { id: 'identity', label: 'Identity', icon: '🆔' },
    { id: 'theme', label: 'Appearance', icon: '✨' },
    { id: 'sections', label: 'Site Modules', icon: '🎨' },
    { id: 'seo', label: 'SEO Engine', icon: '📈' },
    { id: 'plan', label: 'Billing', icon: '💳' },
    { id: 'security', label: 'Security', icon: '🔒' }
  ];

  const sectionTabs = [
    { id: 'homepage', label: 'Homepage' },
    { id: 'about', label: 'About' },
    { id: 'admissions', label: 'Admissions' },
    { id: 'academics', label: 'Academics' },
    { id: 'news', label: 'News & Media' },
    { id: 'studentLife', label: 'Student Life' },
    { id: 'portal', label: 'Student Portal' }
  ];

  return (
    <div className="max-w-7xl mx-auto px-6 py-12">
      <div className="flex flex-col md:flex-row justify-between items-center mb-12 gap-8">
         <div className="flex items-center gap-6">
            <img src={inst.logo} className="w-20 h-20 rounded-3xl shadow-xl border p-2 bg-white object-contain" />
            <div>
               <h1 className="text-4xl font-black text-slate-900 tracking-tight">{inst.name}</h1>
               <div className="flex items-center gap-3 mt-1">
                  <span className={`px-3 py-1 rounded-full text-[8px] font-black uppercase tracking-widest ${inst.plan === SubscriptionPlan.FREE ? 'bg-slate-100' : 'bg-blue-600 text-white'}`}>{inst.plan} Plan</span>
                  <span className="text-[10px] font-bold text-slate-400">Trust Score: {inst.trustScore}%</span>
               </div>
            </div>
         </div>
         <div className="flex gap-4">
           <a href={`#/school/${inst.slug}`} target="_blank" className="bg-white border px-6 py-4 rounded-3xl font-black uppercase tracking-widest text-[10px] shadow-sm hover:bg-slate-50 transition-all">View Site</a>
           <button onClick={() => alert('Changes saved locally!')} className="bg-slate-900 text-white px-8 py-4 rounded-3xl font-black uppercase tracking-widest text-[10px] shadow-2xl hover:scale-105 transition-all">Publish Changes</button>
         </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-12">
         <aside className="lg:col-span-1 space-y-2">
            {tabs.map(t => (
               <button 
                 key={t.id} 
                 onClick={() => setActiveTab(t.id as any)}
                 className={`w-full flex items-center p-5 rounded-2xl font-black uppercase tracking-widest text-[10px] transition-all ${activeTab === t.id ? 'bg-slate-900 text-white shadow-xl' : 'text-slate-500 hover:bg-slate-100'}`}
               >
                  <span className="text-xl mr-4">{t.icon}</span>
                  {t.label}
               </button>
            ))}
         </aside>

         <div className="lg:col-span-3">
            {activeTab === 'identity' && (
              <div className="bg-white p-10 rounded-[40px] border border-slate-100 shadow-sm space-y-10 animate-in fade-in duration-500">
                <h2 className="text-2xl font-black text-slate-900">Basic Information</h2>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                   <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Institution Name</label>
                      <input className="w-full bg-slate-50 border-none rounded-2xl px-6 py-4 font-bold text-slate-900" value={inst.name} onChange={e => handleUpdate({...inst, name: e.target.value})} />
                   </div>
                   <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Region (MoET Mandatory)</label>
                      <select className="w-full bg-slate-50 border-none rounded-2xl px-6 py-4 font-bold text-slate-900 appearance-none" value={inst.region} onChange={e => handleUpdate({...inst, region: e.target.value as Region})}>
                         {Object.values(Region).map(r => <option key={r} value={r}>{r}</option>)}
                      </select>
                   </div>
                   <div className="md:col-span-2">
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Physical Address</label>
                      <input className="w-full bg-slate-50 border-none rounded-2xl px-6 py-4 font-bold text-slate-900" value={inst.contact.address} onChange={e => handleUpdate({...inst, contact: {...inst.contact, address: e.target.value}})} />
                   </div>
                   <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Phone</label>
                      <input className="w-full bg-slate-50 border-none rounded-2xl px-6 py-4 font-bold text-slate-900" value={inst.contact.phone} onChange={e => handleUpdate({...inst, contact: {...inst.contact, phone: e.target.value}})} />
                   </div>
                   <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Official Email</label>
                      <input className="w-full bg-slate-50 border-none rounded-2xl px-6 py-4 font-bold text-slate-900" value={inst.contact.email} onChange={e => handleUpdate({...inst, contact: {...inst.contact, email: e.target.value}})} />
                   </div>
                   <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Office Hours</label>
                      <input className="w-full bg-slate-50 border-none rounded-2xl px-6 py-4 font-bold text-slate-900" placeholder="e.g. Mon-Fri 08:00 - 16:00" value={inst.contact.officeHours} onChange={e => handleUpdate({...inst, contact: {...inst.contact, officeHours: e.target.value}})} />
                   </div>
                   <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Official Website</label>
                      <input className="w-full bg-slate-50 border-none rounded-2xl px-6 py-4 font-bold text-slate-900" placeholder="https://..." value={inst.contact.website || ''} onChange={e => handleUpdate({...inst, contact: {...inst.contact, website: e.target.value}})} />
                   </div>
                </div>
              </div>
            )}

            {activeTab === 'theme' && (
              <div className="bg-white p-10 rounded-[40px] border border-slate-100 shadow-sm space-y-12 animate-in fade-in duration-500">
                <h2 className="text-2xl font-black text-slate-900">Appearance & Branding</h2>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
                   <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Primary Brand Color</label>
                      <div className="flex gap-4 flex-wrap">
                         {['#2563eb', '#1e40af', '#059669', '#7c3aed', '#db2777', '#ea580c', '#111827'].map(color => (
                           <button 
                             key={color} 
                             onClick={() => handleUpdate({...inst, theme: {...inst.theme, primaryColor: color}})}
                             className={`w-10 h-10 rounded-full border-4 transition-all ${inst.theme.primaryColor === color ? 'border-slate-900 scale-110' : 'border-transparent'}`}
                             style={{backgroundColor: color}}
                           />
                         ))}
                         <input 
                           type="color" 
                           className="w-10 h-10 rounded-full bg-transparent border-none cursor-pointer p-0" 
                           value={inst.theme.primaryColor} 
                           onChange={e => handleUpdate({...inst, theme: {...inst.theme, primaryColor: e.target.value}})} 
                         />
                      </div>
                   </div>

                   <div>
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Typography (Font Family)</label>
                      <div className="grid grid-cols-1 gap-3">
                         {['Inter', 'Serif', 'Mono'].map(font => (
                           <button 
                             key={font}
                             onClick={() => handleUpdate({...inst, theme: {...inst.theme, fontFamily: font}})}
                             className={`text-left px-6 py-4 rounded-2xl border-2 transition-all font-bold ${inst.theme.fontFamily === font ? 'border-slate-900 bg-slate-900 text-white' : 'border-slate-100 text-slate-600 hover:border-slate-200'}`}
                             style={{fontFamily: font === 'Inter' ? 'Inter' : font === 'Serif' ? 'Georgia' : 'monospace'}}
                           >
                             {font}
                           </button>
                         ))}
                      </div>
                   </div>
                </div>
              </div>
            )}

            {activeTab === 'sections' && (
              <div className="space-y-8 animate-in fade-in duration-500">
                <div className="flex bg-white p-2 rounded-2xl shadow-sm border border-slate-100 overflow-x-auto whitespace-nowrap scrollbar-hide">
                   {sectionTabs.map(st => (
                     <button key={st.id} onClick={() => setActiveSectionTab(st.id as any)} className={`px-6 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeSectionTab === st.id ? 'bg-slate-900 text-white shadow-xl' : 'text-slate-400 hover:text-slate-600'}`}>{st.label}</button>
                   ))}
                </div>

                <div className="bg-white p-10 rounded-[40px] border border-slate-100 shadow-sm min-h-[600px]">
                   {activeSectionTab === 'about' && (
                     <div className="space-y-12">
                        {/* 1. Institutional Overview */}
                        <section className="space-y-6 pb-12 border-b">
                           <h3 className="text-xl font-black text-slate-900">1. Institutional Overview</h3>
                           <div>
                              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Short Description (150–200 words)</label>
                              <textarea rows={6} className="w-full bg-slate-50 border-none rounded-2xl px-6 py-4 font-medium" value={inst.sections.about.overview} onChange={e => updateSectionField('about', 'overview', e.target.value)} />
                           </div>
                           <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                              <div>
                                 <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Established Year</label>
                                 <input type="number" className="w-full bg-slate-50 border-none rounded-xl px-4 py-3 font-bold" value={inst.metadata.establishedYear} onChange={e => handleUpdate({...inst, metadata: {...inst.metadata, establishedYear: parseInt(e.target.value)}})} />
                              </div>
                           </div>
                        </section>

                        {/* 2. History */}
                        <section className="space-y-6 pb-12 border-b">
                           <h3 className="text-xl font-black text-slate-900">2. History</h3>
                           <div>
                              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Founding Background</label>
                              <textarea rows={4} className="w-full bg-slate-50 border-none rounded-2xl px-6 py-4 font-medium" value={inst.sections.about.history.foundingBackground} onChange={e => updateAboutSubField('history', 'foundingBackground', e.target.value)} />
                           </div>
                           <div>
                              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Growth & Development Summary</label>
                              <textarea rows={4} className="w-full bg-slate-50 border-none rounded-2xl px-6 py-4 font-medium" value={inst.sections.about.history.growthSummary} onChange={e => updateAboutSubField('history', 'growthSummary', e.target.value)} />
                           </div>
                        </section>

                        {/* 3. Vision Statement */}
                        <section className="space-y-6 pb-12 border-b">
                           <h3 className="text-xl font-black text-slate-900">3. Vision Statement</h3>
                           <div>
                              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Vision Statement</label>
                              <input className="w-full bg-slate-50 border-none rounded-xl px-4 py-3 font-bold" value={inst.sections.about.vision.statement} onChange={e => updateAboutSubField('vision', 'statement', e.target.value)} />
                           </div>
                           <div>
                              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Vision Explanation</label>
                              <textarea rows={3} className="w-full bg-slate-50 border-none rounded-2xl px-6 py-4 font-medium" value={inst.sections.about.vision.explanation} onChange={e => updateAboutSubField('vision', 'explanation', e.target.value)} />
                           </div>
                        </section>

                        {/* 4. Mission Statement */}
                        <section className="space-y-6 pb-12 border-b">
                           <h3 className="text-xl font-black text-slate-900">4. Mission Statement</h3>
                           <div>
                              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Mission Statement</label>
                              <input className="w-full bg-slate-50 border-none rounded-xl px-4 py-3 font-bold" value={inst.sections.about.mission.statement} onChange={e => updateAboutSubField('mission', 'statement', e.target.value)} />
                           </div>
                           <div>
                              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Mission Description</label>
                              <textarea rows={3} className="w-full bg-slate-50 border-none rounded-2xl px-6 py-4 font-medium" value={inst.sections.about.mission.description} onChange={e => updateAboutSubField('mission', 'description', e.target.value)} />
                           </div>
                        </section>

                        {/* 5. Core Values */}
                        <section className="space-y-6 pb-12 border-b">
                           <h3 className="text-xl font-black text-slate-900">5. Core Values</h3>
                           <div className="space-y-4">
                              {inst.sections.about.coreValues.map((val, idx) => (
                                <div key={idx} className="p-4 bg-slate-50 rounded-2xl grid grid-cols-1 md:grid-cols-2 gap-4">
                                   <input className="bg-white px-3 py-2 rounded-lg font-bold" value={val.name} onChange={e => {
                                      const newVal = [...inst.sections.about.coreValues];
                                      newVal[idx].name = e.target.value;
                                      updateSectionField('about', 'coreValues', newVal);
                                   }} />
                                   <input className="bg-white px-3 py-2 rounded-lg" value={val.description} onChange={e => {
                                      const newVal = [...inst.sections.about.coreValues];
                                      newVal[idx].description = e.target.value;
                                      updateSectionField('about', 'coreValues', newVal);
                                   }} />
                                </div>
                              ))}
                              <button className="w-full py-3 border-2 border-dashed border-slate-200 rounded-2xl text-[10px] font-black uppercase tracking-widest">+ Add Core Value</button>
                           </div>
                        </section>

                        {/* 6. Leadership Profile */}
                        <section className="space-y-6 pb-12 border-b">
                           <h3 className="text-xl font-black text-slate-900">6. Leadership Profile</h3>
                           <div className="p-8 bg-blue-50 rounded-[32px] space-y-4">
                              <h4 className="font-black text-blue-900 text-sm">Principal / Head of Institution</h4>
                              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                 <input placeholder="Full Name" className="bg-white px-4 py-2 rounded-xl font-bold" value={inst.sections.about.leadership.principal.name} onChange={e => updateAboutSubField('leadership', 'principal', {...inst.sections.about.leadership.principal, name: e.target.value})} />
                                 <input placeholder="Title" className="bg-white px-4 py-2 rounded-xl" value={inst.sections.about.leadership.principal.title} onChange={e => updateAboutSubField('leadership', 'principal', {...inst.sections.about.leadership.principal, title: e.target.value})} />
                                 <input placeholder="Qualifications" className="bg-white px-4 py-2 rounded-xl" value={inst.sections.about.leadership.principal.qualifications} onChange={e => updateAboutSubField('leadership', 'principal', {...inst.sections.about.leadership.principal, qualifications: e.target.value})} />
                                 <input placeholder="Years of Experience" className="bg-white px-4 py-2 rounded-xl" value={inst.sections.about.leadership.principal.experience} onChange={e => updateAboutSubField('leadership', 'principal', {...inst.sections.about.leadership.principal, experience: e.target.value})} />
                              </div>
                              <textarea placeholder="Professional Background" rows={4} className="w-full bg-white px-4 py-3 rounded-xl" value={inst.sections.about.leadership.principal.background} onChange={e => updateAboutSubField('leadership', 'principal', {...inst.sections.about.leadership.principal, background: e.target.value})} />
                              <textarea placeholder="Message from Principal" rows={4} className="w-full bg-white px-4 py-3 rounded-xl" value={inst.sections.about.leadership.principal.message} onChange={e => updateAboutSubField('leadership', 'principal', {...inst.sections.about.leadership.principal, message: e.target.value})} />
                           </div>
                        </section>

                        {/* 7. Accreditation */}
                        <section className="space-y-6 pb-12 border-b">
                           <h3 className="text-xl font-black text-slate-900">7. Accreditation & Affiliations</h3>
                           <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                              <input placeholder="Registered with" className="bg-slate-50 px-4 py-2 rounded-xl font-bold" value={inst.sections.about.accreditation.registeredWith} onChange={e => updateAboutSubField('accreditation', 'registeredWith', e.target.value)} />
                              <input placeholder="Registration Number" className="bg-slate-50 px-4 py-2 rounded-xl" value={inst.sections.about.accreditation.registrationNumber} onChange={e => updateAboutSubField('accreditation', 'registrationNumber', e.target.value)} />
                              <input placeholder="Examination Body" className="bg-slate-50 px-4 py-2 rounded-xl" value={inst.sections.about.accreditation.examinationBody} onChange={e => updateAboutSubField('accreditation', 'examinationBody', e.target.value)} />
                           </div>
                        </section>

                        {/* 8. Institutional Statistics */}
                        <section className="space-y-6 pb-12 border-b">
                           <h3 className="text-xl font-black text-slate-900">8. Institutional Statistics</h3>
                           <div className="grid grid-cols-2 md:grid-cols-5 gap-4">
                              <input type="number" placeholder="Students" className="bg-slate-50 px-4 py-2 rounded-xl font-bold" value={inst.sections.about.statistics.totalStudents} onChange={e => updateAboutSubField('statistics', 'totalStudents', parseInt(e.target.value))} />
                              <input type="number" placeholder="Staff" className="bg-slate-50 px-4 py-2 rounded-xl font-bold" value={inst.sections.about.statistics.totalStaff} onChange={e => updateAboutSubField('statistics', 'totalStaff', parseInt(e.target.value))} />
                              <input placeholder="Ratio" className="bg-slate-50 px-4 py-2 rounded-xl font-bold" value={inst.sections.about.statistics.studentTeacherRatio} onChange={e => updateAboutSubField('statistics', 'studentTeacherRatio', e.target.value)} />
                              <input type="number" placeholder="Years" className="bg-slate-50 px-4 py-2 rounded-xl font-bold" value={inst.sections.about.statistics.yearsOfOperation} onChange={e => updateAboutSubField('statistics', 'yearsOfOperation', parseInt(e.target.value))} />
                              <input placeholder="Graduation %" className="bg-slate-50 px-4 py-2 rounded-xl font-bold" value={inst.sections.about.statistics.graduationRate} onChange={e => updateAboutSubField('statistics', 'graduationRate', e.target.value)} />
                           </div>
                        </section>

                        {/* 9. Campus & Facilities */}
                        <section className="space-y-6">
                           <h3 className="text-xl font-black text-slate-900">9. Campus & Facilities</h3>
                           <textarea rows={4} className="w-full bg-slate-50 border-none rounded-2xl px-6 py-4 font-medium" placeholder="Describe your available facilities..." value={inst.sections.about.facilities.overview} onChange={e => updateAboutSubField('facilities', 'overview', e.target.value)} />
                        </section>
                     </div>
                   )}

                   {activeSectionTab === 'homepage' && (
                     <div className="space-y-10">
                        <div>
                           <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Hero Banner Image URL</label>
                           <input className="w-full bg-slate-50 border-none rounded-2xl px-6 py-4 font-bold" value={inst.sections.homepage.heroBanner} onChange={e => updateSectionField('homepage', 'heroBanner', e.target.value)} />
                        </div>
                        <div>
                           <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Welcome Message</label>
                           <textarea rows={4} className="w-full bg-slate-50 border-none rounded-2xl px-6 py-4 font-medium" value={inst.sections.homepage.welcomeMessage} onChange={e => updateSectionField('homepage', 'welcomeMessage', e.target.value)} />
                        </div>
                     </div>
                   )}
                </div>
              </div>
            )}
         </div>
      </div>
    </div>
  );
};

export default InstitutionAdminDashboard;

export enum Region {
  HHOHHO = 'Hhohho',
  MANZINI = 'Manzini',
  LUBOMBO = 'Lubombo',
  SHISELWENI = 'Shiselweni'
}

export enum InstitutionType {
  PRIMARY = 'Primary',
  HIGH_SCHOOL = 'High School',
  TERTIARY = 'Tertiary',
  PRIVATE = 'Private',
  PUBLIC = 'Public'
}

export enum SubscriptionPlan {
  FREE = 'Free',
  PREMIUM = 'Premium',
  ENTERPRISE = 'Enterprise'
}

export enum UserRole {
  SUPER_ADMIN = 'Super Admin',
  INSTITUTION_ADMIN = 'Institution Admin',
  VISITOR = 'Visitor'
}

export enum GenderType {
  BOYS = 'Boys',
  GIRLS = 'Girls',
  MIXED = 'Mixed'
}

export interface QuickLink {
  label: string;
  url: string;
}

export interface Announcement {
  id: string;
  title: string;
  date: string;
  content: string;
  isFeatured: boolean;
}

export interface CoreValue {
  name: string;
  description: string;
}

export interface Milestone {
  year: string;
  event: string;
}

export interface LeadershipMember {
  name: string;
  title: string;
  description: string;
  photo?: string;
}

export interface AcademicProgram {
  id: string;
  name: string;
  duration: string;
  description: string;
}

export interface BlogPost {
  id: string;
  title: string;
  date: string;
  excerpt: string;
  image: string;
}

export interface EventItem {
  id: string;
  title: string;
  date: string;
  location: string;
}

export interface SEOMetadata {
  title: string;
  description: string;
  keywords: string[];
  healthScore: number;
}

export interface Institution {
  id: string;
  name: string;
  slug: string;
  subdomain?: string;
  logo: string;
  coverImage: string;
  region: Region;
  type: InstitutionType[];
  isVerified: boolean;
  isAccredited: boolean;
  moetRegistration: string;
  isFeatured: boolean;
  trustScore: number;
  plan: SubscriptionPlan;
  status: 'pending' | 'published' | 'suspended';
  seo: SEOMetadata;
  theme: {
    primaryColor: string;
    fontFamily: string;
    borderRadius: string;
    layout: string;
  };
  metadata: {
    gender: GenderType;
    isBoarding: boolean;
    feeRange: { min: number; max: number };
    establishedYear: number;
    studentCount: number;
    hasStudentPortal: boolean;
  };
  contact: {
    address: string;
    phone: string;
    email: string;
    website?: string;
    officeHours: string;
    googleMapsUrl?: string;
    facebook?: string;
    twitter?: string;
    linkedin?: string;
  };
  sections: {
    homepage: {
      heroBanner: string;
      welcomeMessage: string;
      principalMessage: {
        text: string;
        name: string;
        photo?: string;
      };
      quickLinks: QuickLink[];
      announcements: Announcement[];
    };
    about: {
      overview: string;
      history: {
        foundingBackground: string;
        milestones: Milestone[];
        growthSummary: string;
      };
      vision: {
        statement: string;
        explanation: string;
      };
      mission: {
        statement: string;
        description: string;
      };
      coreValues: CoreValue[];
      leadership: {
        principal: {
          name: string;
          title: string;
          qualifications: string;
          experience: string;
          background: string;
          message: string;
          photo?: string;
        };
        seniorTeam: LeadershipMember[];
      };
      accreditation: {
        registeredWith: string;
        registrationNumber: string;
        examinationBody: string;
        affiliations: string[];
        awards: string[];
      };
      statistics: {
        totalStudents: number;
        totalStaff: number;
        studentTeacherRatio: string;
        yearsOfOperation: number;
        graduationRate: string;
      };
      facilities: {
        overview: string;
        list: string[];
      };
      community: {
        outreach: string;
        partnerships: string;
        socialResponsibility: string;
      };
      downloads: { label: string; url: string }[];
      testimonials: { author: string; text: string }[];
    };
    admissions: {
      headline: string;
      introduction: string;
      programs: { level: string; items: string[] }[];
      requirements: {
        academic: string[];
        documents: string[];
        additional: string[];
      };
      processSteps: { step: string; instruction: string }[];
      applicationFee: {
        amount: string;
        methods: string[];
      };
      processingTime: string;
      importantDates: { event: string; date: string }[];
      tuitionFees: {
        perTerm: string;
        perYear: string;
        additional: { label: string; amount: string }[];
      };
      scholarships: {
        types: string[];
        eligibility: string;
        howToApply: string;
      };
      internationalStudents?: string;
      faqs: { question: string; answer: string }[];
      contact: {
        name: string;
        phone: string;
        email: string;
        hours: string;
      };
      allowOnlineApplications: boolean;
      onlineApplicationUrl?: string;
      scholarshipApplicationLink?: string;
    };
    academics: {
      programs: AcademicProgram[];
      departments: string[];
      staff: LeadershipMember[];
      calendarUrl?: string;
      researchOverview?: string;
    };
    news: {
      posts: BlogPost[];
      events: EventItem[];
      gallery: string[];
      videos: string[];
