        <div className="absolute inset-0 bg-gradient-to-t from-slate-900 via-slate-900/40 to-transparent" />
        <div className="absolute bottom-0 left-0 w-full p-8 md:p-12">
          <div className="max-w-7xl mx-auto flex flex-col md:flex-row items-end gap-10">
            <div className="w-40 h-40 bg-white p-5 shadow-2xl shrink-0 mb-[-80px] md:mb-[-120px] z-10 overflow-hidden" style={{ borderRadius: themeStyle['--radius' as any] }}>
              <img src={inst.logo} className="w-full h-full object-contain" />
            </div>
            <div className="flex-1 pb-2 text-white">
               <span className="text-[10px] font-black uppercase tracking-widest opacity-70">{inst.region} Region</span>
               <h1 className="text-4xl md:text-7xl font-black tracking-tighter leading-none mt-2">{inst.name}</h1>
            </div>
          </div>
        </div>
      </div>

      {/* Sticky Navigation */}
      <div className="bg-white border-b sticky top-0 z-50 shadow-sm overflow-x-auto">
        <div className="max-w-7xl mx-auto px-8 md:px-12 flex space-x-10 h-20 items-center">
           <div className="w-40 shrink-0 hidden md:block" />
           {sections.map(s => (
             <button 
               key={s.id} 
               onClick={() => setActiveSection(s.id)} 
               className={`text-[10px] font-black uppercase tracking-widest border-b-4 h-full flex items-center px-1 transition-all ${activeSection === s.id ? 'text-slate-900' : 'text-slate-400'}`} 
               style={{ borderBottomColor: activeSection === s.id ? inst.theme.primaryColor : 'transparent' }}
             >
               {s.label}
             </button>
           ))}
        </div>
      </div>

      <div className="max-w-7xl mx-auto px-8 md:px-12 py-24">
         <div className="grid grid-cols-1 lg:grid-cols-3 gap-16">
            <div className="lg:col-span-2 space-y-32">

               {activeSection === 'admissions' && (
                 <div className="space-y-32 animate-in fade-in slide-in-from-bottom-6 duration-700">
                    {/* Admissions Hero */}
                    <div className="p-12 text-white space-y-10" style={{backgroundColor: inst.theme.primaryColor, borderRadius: themeStyle['--radius' as any]}}>
                       <h2 className="text-5xl font-black tracking-tight">{inst.sections.admissions.headline}</h2>
                       <p className="text-xl font-medium leading-relaxed opacity-90">{inst.sections.admissions.introduction}</p>
                       <div className="flex flex-wrap gap-4">
                          {inst.sections.admissions.allowOnlineApplications && (
                            <a href={inst.sections.admissions.onlineApplicationUrl} target="_blank" className="bg-white text-slate-900 px-8 py-4 rounded-2xl font-black uppercase tracking-widest text-[10px]">Start Application</a>
                          )}
                          <button className="bg-slate-900 text-white px-8 py-4 rounded-2xl font-black uppercase tracking-widest text-[10px]">Download Prospectus</button>
                       </div>
                    </div>

                    {/* Entry Levels */}
                    <section className="space-y-12">
                       <h3 className="text-3xl font-black text-slate-900">Entry Levels & Programs</h3>
                       <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                          {inst.sections.admissions.programs.map((p, i) => (
                            <div key={i} className="p-10 bg-white border rounded-[32px]">
                               <h4 className="text-sm font-black text-slate-400 uppercase tracking-widest mb-6">{p.level}</h4>
                               <div className="flex flex-wrap gap-3">
                                  {p.items.map(item => (
                                    <span key={item} className="px-4 py-2 bg-slate-50 border rounded-xl text-xs font-bold text-slate-700">{item}</span>
                                  ))}
                               </div>
                            </div>
                          ))}
                       </div>
                    </section>

                    {/* Requirements Grid */}
                    <section className="space-y-12">
                       <h3 className="text-3xl font-black text-slate-900">Admission Requirements</h3>
                       <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
                          <div className="space-y-6">
                             <h4 className="text-[10px] font-black text-blue-600 uppercase tracking-widest">Academic Portfolio</h4>
                             <ul className="space-y-4">
                                {inst.sections.admissions.requirements.academic.map((req, i) => (
                                  <li key={i} className="flex gap-4 items-center font-bold text-slate-700">
                                     <span className="w-2 h-2 rounded-full bg-blue-600" /> {req}
                                  </li>
                                ))}
                             </ul>
                          </div>
                          <div className="space-y-6">
                             <h4 className="text-[10px] font-black text-emerald-600 uppercase tracking-widest">Mandatory Documents</h4>
                             <ul className="space-y-4">
                                {inst.sections.admissions.requirements.documents.map((req, i) => (
                                  <li key={i} className="flex gap-4 items-center font-bold text-slate-700">
                                     <span className="w-2 h-2 rounded-full bg-emerald-600" /> {req}
                                  </li>
                                ))}
                             </ul>
                          </div>
                       </div>
                    </section>

                    {/* Process Steps */}
                    <section className="space-y-12">
                       <h3 className="text-3xl font-black text-slate-900">The Application Journey</h3>
                       <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                          {inst.sections.admissions.processSteps.map((step, i) => (
                            <div key={i} className="relative p-8 bg-slate-50 rounded-[32px] border group hover:bg-white transition-all">
                               <div className="absolute -top-4 -left-4 w-12 h-12 bg-slate-900 text-white flex items-center justify-center font-black rounded-2xl group-hover:bg-blue-600 transition-colors">{step.step}</div>
                               <p className="font-bold text-slate-700 pt-4">{step.instruction}</p>
                            </div>
                          ))}
                       </div>
                    </section>

                    {/* Fees & Scholarships */}
                    <section className="grid grid-cols-1 md:grid-cols-2 gap-12">
                       <div className="space-y-8">
                          <h3 className="text-2xl font-black text-slate-900">Fees Structure</h3>
                          <div className="p-10 bg-white border rounded-[32px] space-y-6 shadow-sm">
                             <div className="flex justify-between items-end border-b pb-6">
                                <div>
                                   <p className="text-[9px] font-black text-slate-400 uppercase">Per Year</p>
                                   <p className="text-3xl font-black text-slate-900">{inst.sections.admissions.tuitionFees.perYear}</p>
                                </div>
                                <div className="text-right">
                                   <p className="text-[9px] font-black text-slate-400 uppercase">Per Term</p>
                                   <p className="text-xl font-bold text-slate-600">{inst.sections.admissions.tuitionFees.perTerm}</p>
                                </div>
                             </div>
                             <div className="space-y-4">
                                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Additional Fees</p>
                                {inst.sections.admissions.tuitionFees.additional.map((f, i) => (
                                  <div key={i} className="flex justify-between text-sm font-bold text-slate-700">
                                     <span>{f.label}</span>
                                     <span>{f.amount}</span>
                                  </div>
                                ))}
                             </div>
                          </div>
                       </div>
                       <div className="space-y-8">
                          <h3 className="text-2xl font-black text-slate-900">Scholarships</h3>
                          <div className="p-10 bg-slate-900 text-white rounded-[32px] space-y-8 shadow-2xl">
                             <div className="flex flex-wrap gap-2">
                                {inst.sections.admissions.scholarships.types.map(t => (
                                  <span key={t} className="px-3 py-1 bg-white/10 rounded-full text-[9px] font-black uppercase tracking-widest">{t}</span>
                                ))}
                             </div>
                             <div>
                                <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2">Eligibility</h4>
                                <p className="text-sm font-medium leading-relaxed">{inst.sections.admissions.scholarships.eligibility}</p>
                             </div>
                             <div>
                                <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2">How to Apply</h4>
                                <p className="text-sm font-medium leading-relaxed italic">{inst.sections.admissions.scholarships.howToApply}</p>
                             </div>
                          </div>
                       </div>
                    </section>

                    {/* FAQ */}
                    <section className="space-y-12">
                       <h3 className="text-3xl font-black text-slate-900">Admissions FAQ</h3>
                       <div className="space-y-4">
                          {inst.sections.admissions.faqs.map((f, i) => (
                            <div key={i} className="p-8 bg-white border rounded-3xl">
                               <h4 className="font-black text-slate-900 mb-2">Q: {f.question}</h4>
                               <p className="text-slate-500 font-medium">A: {f.answer}</p>
                            </div>
                          ))}
                       </div>
                    </section>
                 </div>
               )}

               {/* Sections omitted for brevity but remain functional */}
               {activeSection === 'homepage' && (
                 <div className="space-y-12">
                   <h2 className="text-5xl font-black text-slate-900">Our Story</h2>
                   <p className="text-2xl text-slate-500 font-medium leading-relaxed">{inst.sections.homepage.welcomeMessage}</p>
                 </div>
               )}

            </div>

            {/* Sidebar with Admissions Contact */}
            <aside className="space-y-12">
               {activeSection === 'admissions' && (
                 <div className="p-10 bg-white border shadow-2xl sticky top-32" style={{borderRadius: themeStyle['--radius' as any]}}>
                    <h3 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-8">Admissions Office</h3>
                    <div className="space-y-10">
                       <div>
                          <p className="text-[9px] font-black text-slate-300 uppercase mb-2">Officer</p>
                          <p className="font-black text-slate-900">{inst.sections.admissions.contact.name}</p>
                       </div>
                       <div>
                          <p className="text-[9px] font-black text-slate-300 uppercase mb-2">Contact</p>
                          <p className="text-sm font-bold text-slate-700">{inst.sections.admissions.contact.phone}</p>
                          <p className="text-sm font-bold" style={{color: inst.theme.primaryColor}}>{inst.sections.admissions.contact.email}</p>
                       </div>
                       <div>
                          <p className="text-[9px] font-black text-slate-300 uppercase mb-2">Office Hours</p>
                          <p className="text-sm font-bold text-slate-700">{inst.sections.admissions.contact.hours}</p>
                       </div>
                       <button className="w-full py-4 text-white font-black uppercase tracking-widest text-[10px] shadow-xl" style={{backgroundColor: inst.theme.primaryColor, borderRadius: '16px'}}>Book an Appointment</button>
                    </div>
                 </div>
               )}
            </aside>
         </div>
      </div>
    </div>
  );
};

export default InstitutionProfile;
